window.QUESTIONS = [
  // ── SCIENCE (1–50) ──────────────────────────────────────────────────────
  { id:1, subject:"science", question:"Through which process do plants make their own food using sunlight?", options:["Digestion","Photosynthesis","Respiration","Germination"], correct:1, trivia:"'Photo' means light and 'synthesis' means to make. A single leaf performs millions of these reactions every second! 🌿", visual:"🌿", difficulty:"easy", hasMap:false, mapState:null },
  { id:2, subject:"science", question:"Which part of the plant absorbs water and minerals from the soil?", options:["Leaves","Stem","Roots","Flowers"], correct:2, trivia:"The roots of a large tree can spread as wide underground as the tree is tall above ground. They anchor the tree AND drink its water! 🌱", visual:"🌱", difficulty:"easy", hasMap:false, mapState:null },
  { id:3, subject:"science", question:"What gas do plants release into the air during photosynthesis?", options:["Carbon dioxide","Nitrogen","Oxygen","Hydrogen"], correct:2, trivia:"One large tree gives enough oxygen for 2 people to breathe for a whole day! Forests are truly the lungs of our planet. 🌳", visual:"🌳", difficulty:"easy", hasMap:false, mapState:null },
  { id:4, subject:"science", question:"Which is the largest land animal on Earth?", options:["Giraffe","African Elephant","Hippopotamus","White Rhinoceros"], correct:1, trivia:"African elephants can weigh up to 7,000 kg — as heavy as 100 adults! Their trunk alone has over 100,000 muscles but zero bones. 🐘", visual:"🐘", difficulty:"easy", hasMap:false, mapState:null },
  { id:5, subject:"science", question:"How many chambers does the human heart have?", options:["2","3","4","5"], correct:2, trivia:"Your heart beats about 100,000 times every day — that's 37 million times a year without ever resting! ❤️", visual:"❤️", difficulty:"easy", hasMap:false, mapState:null },
  { id:6, subject:"science", question:"What is the hardest substance in the human body?", options:["Bone","Nail","Tooth enamel","Cartilage"], correct:2, trivia:"Tooth enamel is even harder than your bones! It's the shiny outer layer of your teeth and protects them from decay. 🦷", visual:"🦷", difficulty:"medium", hasMap:false, mapState:null },
  { id:7, subject:"science", question:"Which planet in our solar system is closest to the Sun?", options:["Venus","Earth","Mars","Mercury"], correct:3, trivia:"Mercury is so close to the Sun that a year there lasts only 88 Earth days! But it has no atmosphere, so nights are freezing cold. 🪐", visual:"☀️", difficulty:"easy", hasMap:false, mapState:null },
  { id:8, subject:"science", question:"The tadpole is the young one of which animal?", options:["Fish","Salamander","Frog","Toad"], correct:2, trivia:"A tadpole breathes through gills like a fish, but as it grows into a frog it develops lungs and legs — one of nature's coolest transformations! 🐸", visual:"🐸", difficulty:"easy", hasMap:false, mapState:null },
  { id:9, subject:"science", question:"What do camels store in their humps?", options:["Water","Fat","Air","Minerals"], correct:1, trivia:"Camel humps store FAT, not water! When food is scarce, the fat is converted to energy and water. A camel can go without water for up to 2 weeks. 🐪", visual:"🐪", difficulty:"medium", hasMap:false, mapState:null },
  { id:10, subject:"science", question:"Which animal uses echolocation to navigate in the dark?", options:["Owl","Bat","Eagle","Dolphin"], correct:1, trivia:"Bats send out sound waves that bounce off objects and return — like a natural sonar! Some bats can detect an object as thin as a human hair. 🦇", visual:"🦇", difficulty:"medium", hasMap:false, mapState:null },
  { id:11, subject:"science", question:"What is the longest bone in the human body?", options:["Spine","Humerus (upper arm)","Femur (thigh bone)","Tibia (shin bone)"], correct:2, trivia:"The femur (thigh bone) makes up about one quarter of your total height! It's also the strongest bone in your body. 🦴", visual:"🦴", difficulty:"medium", hasMap:false, mapState:null },
  { id:12, subject:"science", question:"What is the smallest bone in the human body?", options:["Finger bone","Stapes (in the ear)","Toe bone","Rib"], correct:1, trivia:"The stapes (stirrup bone) in your middle ear is only 3 mm long — about the size of a grain of rice — yet it helps you hear all sounds! 👂", visual:"👂", difficulty:"hard", hasMap:false, mapState:null },
  { id:13, subject:"science", question:"Through which organ do fish breathe?", options:["Lungs","Skin","Gills","Mouth"], correct:2, trivia:"Fish gills extract dissolved oxygen directly from water. Some fish can absorb oxygen through their skin too, letting them survive out of water briefly! 🐟", visual:"🐟", difficulty:"easy", hasMap:false, mapState:null },
  { id:14, subject:"science", question:"Which of these is a carnivore (meat-eater)?", options:["Cow","Rabbit","Lion","Deer"], correct:2, trivia:"Lions are apex predators — meaning no other animal hunts them. A lion's roar can be heard from 8 km away, used to mark their territory! 🦁", visual:"🦁", difficulty:"easy", hasMap:false, mapState:null },
  { id:15, subject:"science", question:"What green pigment in leaves helps plants make food?", options:["Melanin","Chlorophyll","Carotene","Hemoglobin"], correct:1, trivia:"Chlorophyll absorbs red and blue light from the sun but reflects green light — that's why leaves look green! In autumn, chlorophyll breaks down revealing yellow and orange colours. 🍃", visual:"🍃", difficulty:"medium", hasMap:false, mapState:null },
  { id:16, subject:"science", question:"How many legs does a spider have?", options:["6","8","10","12"], correct:1, trivia:"Spiders are NOT insects! Insects have 6 legs; spiders are arachnids with 8 legs. A spider's web is stronger than steel of the same thickness! 🕷️", visual:"🕷️", difficulty:"easy", hasMap:false, mapState:null },
  { id:17, subject:"science", question:"The Sun is a ____.", options:["Planet","Moon","Star","Comet"], correct:2, trivia:"Our Sun is a medium-sized star. It's so large that about 1.3 million Earths could fit inside it! It converts 4 million tonnes of mass into energy every single second. ☀️", visual:"☀️", difficulty:"easy", hasMap:false, mapState:null },
  { id:18, subject:"science", question:"How many days does Earth take to complete one full orbit around the Sun?", options:["28","30","365","24"], correct:2, trivia:"Earth travels at 107,000 km/h around the Sun — that's 30 km every single second! Yet we can't feel it because everything around us moves at the same speed. 🌍", visual:"🌍", difficulty:"easy", hasMap:false, mapState:null },
  { id:19, subject:"science", question:"Which of these is an example of a simple machine?", options:["Television","Ramp (inclined plane)","Refrigerator","Computer"], correct:1, trivia:"There are 6 types of simple machines: inclined plane, lever, wedge, screw, wheel & axle, and pulley. All complex machines are combinations of these! ⚙️", visual:"⚙️", difficulty:"medium", hasMap:false, mapState:null },
  { id:20, subject:"science", question:"What type of material is attracted to a magnet?", options:["Wood","Plastic","Iron","Glass"], correct:2, trivia:"Magnets attract iron, cobalt, and nickel. The Earth itself is a giant magnet — that's how compass needles always point North! 🧲", visual:"🧲", difficulty:"easy", hasMap:false, mapState:null },
  { id:21, subject:"science", question:"Which organ in the human body controls all its functions?", options:["Heart","Stomach","Liver","Brain"], correct:3, trivia:"Your brain contains about 86 billion nerve cells called neurons! It uses 20% of the body's energy even though it weighs only 2% of total body weight. 🧠", visual:"🧠", difficulty:"easy", hasMap:false, mapState:null },
  { id:22, subject:"science", question:"What do we call animals that eat both plants and animals?", options:["Herbivores","Carnivores","Omnivores","Decomposers"], correct:2, trivia:"Humans are omnivores! Bears, crows, and pigs are omnivores too. The word comes from Latin: 'omni' (all) + 'vorare' (to eat). 🐻", visual:"🐻", difficulty:"easy", hasMap:false, mapState:null },
  { id:23, subject:"science", question:"In the water cycle, water vapour rises and cools to form clouds. This process is called __?", options:["Evaporation","Condensation","Precipitation","Absorption"], correct:1, trivia:"Every drop of water you drink has been part of the water cycle for millions of years — you might be drinking the same water a dinosaur drank! 💧", visual:"💧", difficulty:"medium", hasMap:false, mapState:null },
  { id:24, subject:"science", question:"How many colours are there in a rainbow?", options:["5","6","7","8"], correct:2, trivia:"The 7 rainbow colours in order are VIBGYOR: Violet, Indigo, Blue, Green, Yellow, Orange, Red. A rainbow is actually a full circle — you just can't see the bottom half from the ground! 🌈", visual:"🌈", difficulty:"easy", hasMap:false, mapState:null },
  { id:25, subject:"science", question:"At what temperature does water boil?", options:["0°C","50°C","100°C","200°C"], correct:2, trivia:"Water boils at 100°C at sea level, but on top of Mount Everest it boils at only 70°C because of lower air pressure. So cooking there takes much longer! 🌡️", visual:"🌡️", difficulty:"easy", hasMap:false, mapState:null },
  { id:26, subject:"science", question:"Which part of a plant makes seeds?", options:["Roots","Stem","Leaves","Flower"], correct:3, trivia:"Flowers attract insects with their colours and nectar. When insects collect nectar, pollen sticks to them and is carried to other flowers — this is called pollination! 🌸", visual:"🌸", difficulty:"easy", hasMap:false, mapState:null },
  { id:27, subject:"science", question:"Which of these animals is a mammal?", options:["Crocodile","Shark","Dolphin","Eagle"], correct:2, trivia:"Dolphins are mammals — they breathe air, give birth to live young, and nurse them with milk! They're also one of the most intelligent animals, able to recognise themselves in mirrors. 🐬", visual:"🐬", difficulty:"medium", hasMap:false, mapState:null },
  { id:28, subject:"science", question:"What kind of soil can hold the most water?", options:["Sandy soil","Loamy soil","Clay soil","Rocky soil"], correct:2, trivia:"Clay soil has the tiniest particles, packed tightly together so water cannot drain quickly. Loamy soil (a mix of sand, silt and clay) is actually best for growing plants! 🪣", visual:"🪣", difficulty:"medium", hasMap:false, mapState:null },
  { id:29, subject:"science", question:"A shadow forms when an object blocks __.", options:["Sound","Air","Light","Water"], correct:2, trivia:"Shadows change length throughout the day! They're longest in the morning and evening (when the Sun is low) and shortest at noon (when the Sun is directly overhead). 🌑", visual:"🌑", difficulty:"easy", hasMap:false, mapState:null },
  { id:30, subject:"science", question:"Which planet is known as the Red Planet?", options:["Venus","Jupiter","Mars","Saturn"], correct:2, trivia:"Mars looks red because its surface is covered in iron oxide — which is just rust! India's Mangalyaan spacecraft successfully reached Mars in 2014 on its very first attempt. 🔴", visual:"🔴", difficulty:"easy", hasMap:false, mapState:null },
  { id:31, subject:"science", question:"What is the outer layer of the Earth called?", options:["Mantle","Crust","Core","Magma"], correct:1, trivia:"The Earth's crust is like the skin of an apple — very thin compared to what's inside! It ranges from 5 km (under oceans) to 70 km thick (under mountains). 🌏", visual:"🌏", difficulty:"medium", hasMap:false, mapState:null },
  { id:32, subject:"science", question:"Which vitamin do we get from sunlight?", options:["Vitamin A","Vitamin B","Vitamin C","Vitamin D"], correct:3, trivia:"When sunlight hits your skin, your body makes Vitamin D! It helps build strong bones and teeth. That's why spending time outdoors is so important. ☀️", visual:"☀️", difficulty:"medium", hasMap:false, mapState:null },
  { id:33, subject:"science", question:"What is the process by which a caterpillar changes into a butterfly?", options:["Mutation","Metamorphosis","Evolution","Reproduction"], correct:1, trivia:"Inside the chrysalis, the caterpillar's body completely dissolves into a soup of cells before rebuilding into a butterfly — one of nature's most magical transformations! 🦋", visual:"🦋", difficulty:"easy", hasMap:false, mapState:null },
  { id:34, subject:"science", question:"Approximately how many bones are in an adult human body?", options:["106","206","306","406"], correct:1, trivia:"Babies are born with about 270-300 bones! As you grow, many fuse together. By adulthood, you're left with 206. Your hands and feet contain more than half of all your bones! 🦴", visual:"🦴", difficulty:"medium", hasMap:false, mapState:null },
  { id:35, subject:"science", question:"Which is the largest organ of the human body?", options:["Liver","Lungs","Brain","Skin"], correct:3, trivia:"Your skin covers about 2 square metres and weighs around 3-4 kg. It constantly renews itself — you shed and regrow your entire outer skin layer every 2-4 weeks! 🧑", visual:"🧑", difficulty:"medium", hasMap:false, mapState:null },
  { id:36, subject:"science", question:"Sound travels fastest through which medium?", options:["Air","Water","Steel","Vacuum"], correct:2, trivia:"Sound travels at 340 m/s through air, about 1,500 m/s through water — but through steel it zips along at 5,000 m/s! That's why you can hear a train coming by pressing your ear to the rail. 🔊", visual:"🔊", difficulty:"hard", hasMap:false, mapState:null },
  { id:37, subject:"science", question:"Which is NOT a source of light?", options:["Sun","Stars","Moon","Firefly"], correct:2, trivia:"The Moon doesn't make its own light — it reflects sunlight! This is why it appears to change shape (phases) as it moves around Earth. 🌕", visual:"🌕", difficulty:"medium", hasMap:false, mapState:null },
  { id:38, subject:"science", question:"Desert plants like cacti store water in their __.", options:["Roots","Stems","Leaves","Flowers"], correct:1, trivia:"Cactus stems can expand like an accordion to store hundreds of litres of water after rain. Their leaves have evolved into spines to reduce water loss. 🌵", visual:"🌵", difficulty:"medium", hasMap:false, mapState:null },
  { id:39, subject:"science", question:"What kind of animals are frogs and toads?", options:["Mammals","Birds","Reptiles","Amphibians"], correct:3, trivia:"Amphibians can live both on land AND in water! The word comes from Greek: 'amphi' (both) + 'bios' (life). They were the first vertebrates to walk on land, over 350 million years ago! 🐊", visual:"🐸", difficulty:"medium", hasMap:false, mapState:null },
  { id:40, subject:"science", question:"What does a plant need to grow? (Choose the best answer)", options:["Sunlight only","Water only","Sunlight, water, air, and minerals","Soil only"], correct:2, trivia:"Plants are the only living things that can make their own food from simple ingredients — sunlight, water, CO₂, and minerals. They're nature's original solar panels! ☀️🌱", visual:"🌱", difficulty:"easy", hasMap:false, mapState:null },
  { id:41, subject:"science", question:"How does a chameleon protect itself from predators?", options:["By running fast","By changing colour","By flying away","By spraying venom"], correct:1, trivia:"Chameleons change colour mainly to communicate mood and temperature — not just for camouflage! Their eyes can move independently, giving them almost 360° vision. 🦎", visual:"🦎", difficulty:"easy", hasMap:false, mapState:null },
  { id:42, subject:"science", question:"Which of these is a renewable source of energy?", options:["Coal","Petroleum","Solar energy","Natural gas"], correct:2, trivia:"The Sun sends more energy to Earth in one hour than all of humanity uses in an entire year! Solar panels can convert that energy into electricity with zero pollution. ☀️⚡", visual:"☀️", difficulty:"medium", hasMap:false, mapState:null },
  { id:43, subject:"science", question:"The force that pulls objects toward the ground is called __.", options:["Magnetism","Friction","Gravity","Electricity"], correct:2, trivia:"Isaac Newton realised the force that pulls an apple to the ground is the same force that keeps the Moon orbiting Earth — he called it gravity in 1687! 🍎", visual:"🍎", difficulty:"easy", hasMap:false, mapState:null },
  { id:44, subject:"science", question:"Which bird cannot fly but is the largest bird in the world?", options:["Penguin","Kiwi","Ostrich","Emu"], correct:2, trivia:"An ostrich can run at 70 km/h — faster than a horse! Their eyes are bigger than their brains. They lay the largest eggs of any living bird. 🐦", visual:"🐦", difficulty:"easy", hasMap:false, mapState:null },
  { id:45, subject:"science", question:"What is the centre of an atom called?", options:["Electron","Neutron","Nucleus","Proton"], correct:2, trivia:"An atom's nucleus contains protons and neutrons, with electrons orbiting around it. Atoms are so tiny that a single grain of sand contains about 43 billion billion atoms! ⚛️", visual:"⚛️", difficulty:"hard", hasMap:false, mapState:null },
  { id:46, subject:"science", question:"Where do plants mainly store their food?", options:["Leaves","Roots and fruits","Stem bark","Flowers"], correct:1, trivia:"Carrots, turnips, and sweet potatoes are roots where plants store food. Apples and mangoes are fruits — they store seeds AND food. So vegetables and fruits are basically plant food stores! 🥕🍎", visual:"🥕", difficulty:"medium", hasMap:false, mapState:null },
  { id:47, subject:"science", question:"What organ in our body fights diseases and infections?", options:["Liver","White blood cells","Kidney","Pancreas"], correct:1, trivia:"White blood cells are your body's soldiers! They patrol your blood, find germs, and destroy them. You have about 7,000 per microlitre of blood — billions of defenders! 🛡️", visual:"🛡️", difficulty:"medium", hasMap:false, mapState:null },
  { id:48, subject:"science", question:"Which of these is an insect?", options:["Spider","Scorpion","Butterfly","Crab"], correct:2, trivia:"Insects always have 3 body parts (head, thorax, abdomen), 6 legs, and usually 2 pairs of wings. There are over 1 million known insect species — more than all other animals combined! 🦋", visual:"🦋", difficulty:"easy", hasMap:false, mapState:null },
  { id:49, subject:"science", question:"What is the force that slows down moving objects due to surface contact?", options:["Gravity","Friction","Magnetism","Tension"], correct:1, trivia:"Friction generates heat — that's how cavemen made fire! It's also why your hands warm up when you rub them together. Without friction, we couldn't walk, drive, or hold anything! 🔥", visual:"🔥", difficulty:"medium", hasMap:false, mapState:null },
  { id:50, subject:"science", question:"The Moon takes approximately how many days to orbit the Earth once?", options:["7 days","14 days","28 days","365 days"], correct:2, trivia:"The Moon always shows the same face to Earth! This is because it rotates once on its axis in exactly the same time it orbits Earth — 28 days. The far side was only photographed in 1959. 🌙", visual:"🌙", difficulty:"medium", hasMap:false, mapState:null },

  // ── GEOGRAPHY (51–100) ──────────────────────────────────────────────────
  { id:51, subject:"geography", question:"What is the capital city of India?", options:["Mumbai","Kolkata","New Delhi","Hyderabad"], correct:2, trivia:"New Delhi was officially declared India's capital in 1911 by the British. Before that, Calcutta (Kolkata) was the capital. The Red Fort and India Gate are iconic landmarks here! 🏛️", visual:"🏛️", difficulty:"easy", hasMap:true, mapState:"Delhi" },
  { id:52, subject:"geography", question:"Which is the longest river in India?", options:["Yamuna","Ganga","Brahmaputra","Godavari"], correct:1, trivia:"The Ganga is 2,525 km long and flows through 5 states. It's called India's national river and is considered sacred by Hindus. Over 400 million people live along its banks! 🌊", visual:"🌊", difficulty:"easy", hasMap:true, mapState:"Uttar Pradesh" },
  { id:53, subject:"geography", question:"India's national bird is the __.", options:["Sparrow","Peacock","Parrot","Flamingo"], correct:1, trivia:"The peacock became India's national bird in 1963. A male peacock's tail feathers (called a 'train') can be longer than 1.5 metres and have beautiful 'eye' patterns! 🦚", visual:"🦚", difficulty:"easy", hasMap:false, mapState:null },
  { id:54, subject:"geography", question:"Which mountain range is located in the north of India?", options:["Vindhyas","Aravalli","Himalayas","Western Ghats"], correct:2, trivia:"The Himalayas are the world's highest mountain range with 14 peaks above 8,000 metres! The word 'Himalaya' comes from Sanskrit meaning 'abode of snow'. 🏔️", visual:"🏔️", difficulty:"easy", hasMap:false, mapState:null },
  { id:55, subject:"geography", question:"Which is the largest ocean in the world?", options:["Atlantic Ocean","Indian Ocean","Arctic Ocean","Pacific Ocean"], correct:3, trivia:"The Pacific Ocean covers more area than ALL the land on Earth combined! The deepest point, Mariana Trench, is 11 km deep — deeper than Mount Everest is tall. 🌊", visual:"🌊", difficulty:"easy", hasMap:false, mapState:null },
  { id:56, subject:"geography", question:"How many continents are there on Earth?", options:["5","6","7","8"], correct:2, trivia:"The 7 continents are Asia, Africa, North America, South America, Europe, Australia, and Antarctica. Asia is the largest — it's bigger than all the other continents combined! 🌍", visual:"🌍", difficulty:"easy", hasMap:false, mapState:null },
  { id:57, subject:"geography", question:"What is the capital of Rajasthan?", options:["Udaipur","Jodhpur","Jaisalmer","Jaipur"], correct:3, trivia:"Jaipur is called the 'Pink City' because in 1876, the entire city was painted pink to welcome Prince Albert of Wales. It's still maintained that colour today! 🏰", visual:"🏰", difficulty:"medium", hasMap:true, mapState:"Rajasthan" },
  { id:58, subject:"geography", question:"Which is the smallest state in India by area?", options:["Kerala","Tripura","Sikkim","Goa"], correct:3, trivia:"Goa is India's smallest state but one of the richest! It was a Portuguese colony until 1961, which is why you'll find many churches and Portuguese-style buildings there. 🏖️", visual:"🏖️", difficulty:"medium", hasMap:true, mapState:"Goa" },
  { id:59, subject:"geography", question:"The river Brahmaputra flows through which Indian state?", options:["West Bengal","Bihar","Assam","Odisha"], correct:2, trivia:"The Brahmaputra is one of the widest rivers in the world! During monsoon, it can be over 15 km wide. It's called 'Son of Brahma' and is one of the few rivers considered masculine. 🏞️", visual:"🏞️", difficulty:"medium", hasMap:true, mapState:"Assam" },
  { id:60, subject:"geography", question:"Which is the highest mountain peak in the world?", options:["K2","Kangchenjunga","Mount Everest","Lhotse"], correct:2, trivia:"Mount Everest stands at 8,849 metres above sea level. Edmund Hillary and Tenzing Norgay Sherpa were the first to reach the summit on 29 May 1953. India's Bachendri Pal was the first Indian woman to climb it in 1984! 🏔️", visual:"🏔️", difficulty:"easy", hasMap:false, mapState:null },
  { id:61, subject:"geography", question:"Which sea lies to the west of India?", options:["Bay of Bengal","South China Sea","Arabian Sea","Andaman Sea"], correct:2, trivia:"The Arabian Sea connects India to the Middle East and Africa. Mumbai (India's largest city) is a major port on the Arabian Sea, and has been a trading hub for over 2,000 years! ⛵", visual:"⛵", difficulty:"easy", hasMap:false, mapState:null },
  { id:62, subject:"geography", question:"Which bay lies to the east of India?", options:["Bay of Bengal","Arabian Sea","Persian Gulf","Red Sea"], correct:0, trivia:"The Bay of Bengal is the world's largest bay! It receives water from major rivers like the Ganga, Brahmaputra, Mahanadi, Godavari, and Krishna. Cyclones often form here. 🌀", visual:"🌀", difficulty:"easy", hasMap:false, mapState:null },
  { id:63, subject:"geography", question:"What is the capital of Maharashtra?", options:["Pune","Nagpur","Aurangabad","Mumbai"], correct:3, trivia:"Mumbai (formerly Bombay) is India's financial capital and is home to Bollywood — the world's largest film industry by number of movies produced each year! 🎬", visual:"🎬", difficulty:"easy", hasMap:true, mapState:"Maharashtra" },
  { id:64, subject:"geography", question:"Which state is called the 'Granary of India'?", options:["Haryana","Punjab","Uttar Pradesh","Madhya Pradesh"], correct:1, trivia:"Punjab produces a huge share of India's wheat and rice. The name 'Punjab' comes from Persian meaning 'Land of Five Rivers'. The Green Revolution of the 1960s transformed Punjab into India's bread basket. 🌾", visual:"🌾", difficulty:"medium", hasMap:true, mapState:"Punjab" },
  { id:65, subject:"geography", question:"Which is the largest country in the world by area?", options:["China","Canada","USA","Russia"], correct:3, trivia:"Russia is so large that it spans 11 time zones! When people in Moscow are having breakfast, people in the far east are already going to bed. It's nearly twice the size of the next largest country. 🗺️", visual:"🗺️", difficulty:"easy", hasMap:false, mapState:null },
  { id:66, subject:"geography", question:"What is the capital of Japan?", options:["Osaka","Kyoto","Tokyo","Hiroshima"], correct:2, trivia:"Tokyo is the most populous city in the world with over 37 million people in its greater metropolitan area! It also has one of the world's most efficient and punctual train networks. 🗼", visual:"🗼", difficulty:"medium", hasMap:false, mapState:null },
  { id:67, subject:"geography", question:"The Amazon Rainforest is located mainly in which country?", options:["Colombia","Venezuela","Peru","Brazil"], correct:3, trivia:"The Amazon Rainforest produces 20% of Earth's oxygen — earning it the nickname 'Lungs of the Earth'. It's home to 10% of all species on our planet, many still undiscovered! 🌿", visual:"🌿", difficulty:"medium", hasMap:false, mapState:null },
  { id:68, subject:"geography", question:"Which is the largest desert in the world?", options:["Sahara","Gobi","Arabian","Antarctic"], correct:3, trivia:"Trick question! Antarctica is technically the world's largest desert because a desert is defined by low rainfall, not heat. The Sahara is the largest HOT desert. 🏜️❄️", visual:"🏜️", difficulty:"hard", hasMap:false, mapState:null },
  { id:69, subject:"geography", question:"What is the capital of Australia?", options:["Sydney","Melbourne","Perth","Canberra"], correct:3, trivia:"Most people think Sydney is Australia's capital, but it's actually Canberra! Canberra was purpose-built as the capital because Sydney and Melbourne couldn't agree on who should have it. 🦘", visual:"🦘", difficulty:"hard", hasMap:false, mapState:null },
  { id:70, subject:"geography", question:"Through which Indian city does the river Yamuna flow?", options:["Varanasi","Allahabad","Delhi","Patna"], correct:2, trivia:"The Yamuna River flows right past the Taj Mahal in Agra before reaching Delhi! The Taj Mahal was built on the banks of the Yamuna in the 17th century. 🕌", visual:"🕌", difficulty:"medium", hasMap:true, mapState:"Delhi" },
  { id:71, subject:"geography", question:"India shares its longest border with which country?", options:["Pakistan","China","Nepal","Bangladesh"], correct:1, trivia:"India shares a 3,488 km long border with Bangladesh — its longest land border! India actually shares land borders with 6 countries: Pakistan, China, Nepal, Bhutan, Bangladesh, and Myanmar. 🌏", visual:"🌏", difficulty:"hard", hasMap:false, mapState:null },
  { id:72, subject:"geography", question:"Which state of India is known as 'God's Own Country'?", options:["Goa","Tamil Nadu","Karnataka","Kerala"], correct:3, trivia:"Kerala earned this nickname because of its beautiful backwaters, lush greenery, and stunning beaches. It has the highest literacy rate in India — nearly 97%! 🌴", visual:"🌴", difficulty:"easy", hasMap:true, mapState:"Kerala" },
  { id:73, subject:"geography", question:"The Thar Desert is located in which Indian state?", options:["Gujarat","Rajasthan","Haryana","Punjab"], correct:1, trivia:"The Thar (Great Indian Desert) is the world's 9th largest hot desert. Despite the harsh conditions, it is one of the most densely populated deserts in the world! 🏜️", visual:"🏜️", difficulty:"medium", hasMap:true, mapState:"Rajasthan" },
  { id:74, subject:"geography", question:"How many Union Territories does India have?", options:["6","7","8","9"], correct:2, trivia:"India has 28 states and 8 Union Territories (UTs). UTs are directly governed by the central government. Delhi and Puducherry are UTs that have their own elected governments! 🇮🇳", visual:"🇮🇳", difficulty:"hard", hasMap:false, mapState:null },
  { id:75, subject:"geography", question:"Which river is known as the 'Sorrow of Bihar'?", options:["Ganga","Son","Kosi","Gandak"], correct:2, trivia:"The Kosi River was called the 'Sorrow of Bihar' because it flooded and changed course frequently, causing massive devastation. A barrage built in 1963 has helped control floods. 🌊", visual:"🌊", difficulty:"hard", hasMap:true, mapState:"Bihar" },
  { id:76, subject:"geography", question:"What is the capital of France?", options:["Berlin","Madrid","Rome","Paris"], correct:3, trivia:"Paris is home to the Eiffel Tower, originally built as a temporary structure for the 1889 World Fair! The French wanted to tear it down, but it was saved because it was useful as a radio tower. 🗼", visual:"🗼", difficulty:"easy", hasMap:false, mapState:null },
  { id:77, subject:"geography", question:"Which is India's southernmost tip?", options:["Rameshwaram","Kanyakumari","Thiruvananthapuram","Tuticorin"], correct:1, trivia:"Kanyakumari is the only place in India where you can watch the sunrise and sunset over the sea! Three oceans meet here — the Arabian Sea, Bay of Bengal, and Indian Ocean. 🌅", visual:"🌅", difficulty:"medium", hasMap:true, mapState:"Tamil Nadu" },
  { id:78, subject:"geography", question:"The Nile River is in which continent?", options:["Asia","South America","Europe","Africa"], correct:3, trivia:"The Nile flows northward through 11 countries and has been the lifeline of Egypt for over 5,000 years. The ancient Egyptian civilisation — with its pyramids and pharaohs — was built on its banks! 🐪", visual:"🐪", difficulty:"easy", hasMap:false, mapState:null },
  { id:79, subject:"geography", question:"What is the capital of Karnataka?", options:["Mysuru","Hubli","Mangaluru","Bengaluru"], correct:3, trivia:"Bengaluru (Bangalore) is called the 'Silicon Valley of India' because it's home to hundreds of tech companies including Infosys, Wipro, and India's space agency ISRO! 💻", visual:"💻", difficulty:"easy", hasMap:true, mapState:"Karnataka" },
  { id:80, subject:"geography", question:"The Great Barrier Reef is located in which country?", options:["USA","Brazil","Australia","India"], correct:2, trivia:"The Great Barrier Reef is the world's largest coral reef system — so large it can be seen from space! It stretches 2,300 km and is home to 9,000 species. 🐠", visual:"🐠", difficulty:"medium", hasMap:false, mapState:null },
  { id:81, subject:"geography", question:"Which is the most populous country in the world (as of 2024)?", options:["USA","Russia","China","India"], correct:3, trivia:"India surpassed China in 2023 to become the world's most populous country with over 1.4 billion people! India adds approximately 1 million people every 2 weeks. 🇮🇳", visual:"🇮🇳", difficulty:"medium", hasMap:false, mapState:null },
  { id:82, subject:"geography", question:"What is the capital of West Bengal?", options:["Patna","Bhubaneswar","Kolkata","Ranchi"], correct:2, trivia:"Kolkata (formerly Calcutta) was India's capital during British rule. It's known as the 'City of Joy' and is home to the famous Howrah Bridge, one of the world's busiest bridges! 🌉", visual:"🌉", difficulty:"easy", hasMap:true, mapState:"West Bengal" },
  { id:83, subject:"geography", question:"Which is the smallest continent?", options:["Europe","Antarctica","Australia","South America"], correct:2, trivia:"Australia is the smallest continent but also an entire country by itself! It's home to unique animals found nowhere else — kangaroos, koalas, platypuses, and emus. 🦘", visual:"🦘", difficulty:"easy", hasMap:false, mapState:null },
  { id:84, subject:"geography", question:"The river Ganga originates from which glacier?", options:["Siachen Glacier","Gangotri Glacier","Zemu Glacier","Pindari Glacier"], correct:1, trivia:"The Ganga originates from Gangotri Glacier in Uttarakhand at an altitude of 3,892 metres. The exact source is called Gaumukh (meaning cow's mouth) because of its shape! ❄️", visual:"❄️", difficulty:"hard", hasMap:true, mapState:"Uttarakhand" },
  { id:85, subject:"geography", question:"In which state is the Kaziranga National Park, home to the one-horned rhino?", options:["West Bengal","Assam","Arunachal Pradesh","Meghalaya"], correct:1, trivia:"Kaziranga has the world's largest population of Indian one-horned rhinoceroses — about 2,600! It also has more tigers per unit area than any other tiger reserve in the world. 🦏", visual:"🦏", difficulty:"medium", hasMap:true, mapState:"Assam" },
  { id:86, subject:"geography", question:"Which city is called the 'Pink City' of India?", options:["Jodhpur","Udaipur","Jaipur","Jaisalmer"], correct:2, trivia:"In 1876, Maharaja Ram Singh ordered Jaipur painted pink — the colour of hospitality — to welcome Prince Albert of Wales. The law still requires buildings in the old city to be pink! 🌸", visual:"🌸", difficulty:"easy", hasMap:true, mapState:"Rajasthan" },
  { id:87, subject:"geography", question:"Which Indian state has the longest coastline?", options:["Maharashtra","Tamil Nadu","Andhra Pradesh","Gujarat"], correct:3, trivia:"Gujarat has a coastline of about 1,600 km — the longest of any Indian state! This is why it has been a major trading state for thousands of years, with famous ports. ⛵", visual:"⛵", difficulty:"hard", hasMap:true, mapState:"Gujarat" },
  { id:88, subject:"geography", question:"What is the capital of Tamil Nadu?", options:["Coimbatore","Madurai","Salem","Chennai"], correct:3, trivia:"Chennai (formerly Madras) is India's gateway to South India. It's known as the 'Detroit of India' because so many car factories are here. Marina Beach in Chennai is one of the world's longest beaches! 🏖️", visual:"🏖️", difficulty:"easy", hasMap:true, mapState:"Tamil Nadu" },
  { id:89, subject:"geography", question:"The Sundarbans mangrove forest is shared between India and which country?", options:["Nepal","Sri Lanka","Bangladesh","Myanmar"], correct:2, trivia:"The Sundarbans is the world's largest mangrove forest and is home to the Royal Bengal Tiger. The name means 'Beautiful Forest' in Bengali. It's a UNESCO World Heritage Site! 🐯", visual:"🐯", difficulty:"hard", hasMap:false, mapState:null },
  { id:90, subject:"geography", question:"What is the capital of the USA?", options:["New York","Los Angeles","Chicago","Washington D.C."], correct:3, trivia:"Washington D.C. was purpose-built as the capital. D.C. stands for 'District of Columbia'. The White House has 132 rooms, 35 bathrooms, and 6 floors! 🏛️", visual:"🏛️", difficulty:"easy", hasMap:false, mapState:null },
  { id:91, subject:"geography", question:"How many states does India have?", options:["25","26","27","28"], correct:3, trivia:"India has 28 states and 8 Union Territories. The most recently formed state is Telangana (2014), which was carved out of Andhra Pradesh. India has 22 officially recognised languages! 🇮🇳", visual:"🇮🇳", difficulty:"medium", hasMap:false, mapState:null },
  { id:92, subject:"geography", question:"In which state is the Siachen Glacier, the world's highest battlefield, located?", options:["Himachal Pradesh","Uttarakhand","Jammu & Kashmir","Sikkim"], correct:2, trivia:"Siachen Glacier at 5,400 metres is the world's second longest non-polar glacier and is the world's highest military battlefield. Indian soldiers have been stationed there since 1984! ❄️", visual:"❄️", difficulty:"hard", hasMap:true, mapState:"Jammu & Kashmir" },
  { id:93, subject:"geography", question:"The Deccan Plateau lies in which part of India?", options:["Northern India","Northeastern India","Peninsular India","Western India"], correct:2, trivia:"The Deccan Plateau is a massive elevated flatland covering most of peninsular India. 'Deccan' comes from Sanskrit 'Dakshin' meaning south. It's rich in mineral resources! ⛰️", visual:"⛰️", difficulty:"medium", hasMap:false, mapState:null },
  { id:94, subject:"geography", question:"Which state in India is known for its tea plantations?", options:["Karnataka","Tamil Nadu","Assam","West Bengal"], correct:2, trivia:"Assam produces about 55% of India's total tea output! Assam tea is known for its rich, malty flavour. The Assam tea bush is one of two main varieties used worldwide. ☕", visual:"☕", difficulty:"easy", hasMap:true, mapState:"Assam" },
  { id:95, subject:"geography", question:"What is the name of the line that divides the Earth into Northern and Southern hemispheres?", options:["Prime Meridian","Tropic of Cancer","Equator","Arctic Circle"], correct:2, trivia:"The Equator passes through 13 countries, and the Ecuadorian people literally named their country 'Ecuador' after it! At the Equator, the Sun rises and sets almost exactly 12 hours apart every day. 🌐", visual:"🌐", difficulty:"easy", hasMap:false, mapState:null },
  { id:96, subject:"geography", question:"The Chilika Lake — India's largest coastal lagoon — is in which state?", options:["Andhra Pradesh","West Bengal","Tamil Nadu","Odisha"], correct:3, trivia:"Chilika Lake is home to millions of migratory birds every winter including flamingoes, pelicans, and herons. It also has a population of Irrawaddy dolphins — extremely rare! 🦢", visual:"🦢", difficulty:"hard", hasMap:true, mapState:"Odisha" },
  { id:97, subject:"geography", question:"India's space agency ISRO is headquartered in which city?", options:["Mumbai","Chennai","Hyderabad","Bengaluru"], correct:3, trivia:"ISRO (Indian Space Research Organisation) was founded in 1969. India became the first country to reach Mars orbit on its very first attempt in 2014 — a feat no other nation has achieved! 🚀", visual:"🚀", difficulty:"medium", hasMap:true, mapState:"Karnataka" },
  { id:98, subject:"geography", question:"Which Indian state shares a border with China, Nepal, Bhutan, and Bangladesh?", options:["Assam","Bihar","Sikkim","West Bengal"], correct:3, trivia:"West Bengal's unique geography gives it borders with 4 countries! Darjeeling in West Bengal is famous for its premium tea and a UNESCO-listed toy train that climbs the Himalayan foothills. 🍵", visual:"🍵", difficulty:"hard", hasMap:true, mapState:"West Bengal" },
  { id:99, subject:"geography", question:"The Western Ghats mountain range runs along which coast of India?", options:["Eastern coast","Northern coast","Western coast","Southern coast"], correct:0, trivia:"The Western Ghats are a UNESCO World Heritage Site and one of the world's top 8 'hottest hotspots' of biological diversity! They receive heavy monsoon rains and are the source of many rivers. 🌧️", visual:"🌧️", difficulty:"medium", hasMap:false, mapState:null },
  { id:100, subject:"geography", question:"What is the capital of Gujarat?", options:["Surat","Ahmedabad","Rajkot","Gandhinagar"], correct:3, trivia:"Trick question! Most people say Ahmedabad, but Gandhinagar is actually Gujarat's capital — named after Mahatma Gandhi, who was born in Gujarat. Ahmedabad is the largest city, not the capital! 🏛️", visual:"🏛️", difficulty:"hard", hasMap:true, mapState:"Gujarat" },

  // ── HISTORY (101–150) ────────────────────────────────────────────────────
  { id:101, subject:"history", question:"India gained independence from British rule on which date?", options:["26 January 1950","15 August 1947","2 October 1869","14 August 1947"], correct:1, trivia:"At the stroke of midnight on 15 August 1947, Jawaharlal Nehru delivered his famous 'Tryst with Destiny' speech as India became free after nearly 200 years of British rule! 🇮🇳", visual:"🇮🇳", difficulty:"easy", hasMap:false, mapState:null },
  { id:102, subject:"history", question:"Who is known as the 'Father of the Nation' of India?", options:["Jawaharlal Nehru","Sardar Patel","Bal Gangadhar Tilak","Mahatma Gandhi"], correct:3, trivia:"Mahatma Gandhi's full name was Mohandas Karamchand Gandhi. 'Mahatma' means 'great soul' in Sanskrit — a title given to him by the people. He was born on 2 October 1869, now celebrated as Gandhi Jayanti! 🕊️", visual:"🕊️", difficulty:"easy", hasMap:false, mapState:null },
  { id:103, subject:"history", question:"Who was India's first Prime Minister?", options:["Lal Bahadur Shastri","Sardar Vallabhbhai Patel","Jawaharlal Nehru","Dr. Rajendra Prasad"], correct:2, trivia:"Jawaharlal Nehru served as India's PM from 1947 to 1964 — the longest tenure of any Indian PM! He loved children so much that Children's Day is celebrated on his birthday, 14 November. 🌹", visual:"🌹", difficulty:"easy", hasMap:false, mapState:null },
  { id:104, subject:"history", question:"Who was the chief architect of the Indian Constitution?", options:["Mahatma Gandhi","Jawaharlal Nehru","Dr. B.R. Ambedkar","Sardar Patel"], correct:2, trivia:"Dr. B.R. Ambedkar chaired the Drafting Committee and worked for 2 years, 11 months and 18 days to create the Indian Constitution. It's the world's longest written national constitution! 📜", visual:"📜", difficulty:"medium", hasMap:false, mapState:null },
  { id:105, subject:"history", question:"India's Constitution came into effect on which date?", options:["15 August 1947","2 October 1950","26 November 1949","26 January 1950"], correct:3, trivia:"26 January 1950 is celebrated as Republic Day because India officially became a Republic on that day — the Constitution came into force. A grand parade is held in New Delhi every year! 🎺", visual:"🎺", difficulty:"medium", hasMap:false, mapState:null },
  { id:106, subject:"history", question:"The Taj Mahal was built by which Mughal emperor?", options:["Akbar","Humayun","Aurangzeb","Shah Jahan"], correct:3, trivia:"Shah Jahan built the Taj Mahal as a memorial for his beloved wife Mumtaz Mahal, who died in 1631. It took 20,000 workers and 22 years to complete! It's made of white marble that changes colour in different light. 🕌", visual:"🕌", difficulty:"easy", hasMap:false, mapState:null },
  { id:107, subject:"history", question:"Who gave the slogan 'Give me blood, I will give you freedom!'?", options:["Mahatma Gandhi","Bhagat Singh","Subhas Chandra Bose","Lala Lajpat Rai"], correct:2, trivia:"Subhas Chandra Bose, known as 'Netaji', formed the Indian National Army (INA) to fight the British. He disappeared mysteriously in 1945 — one of India's greatest unsolved mysteries! ✊", visual:"✊", difficulty:"medium", hasMap:false, mapState:null },
  { id:108, subject:"history", question:"The Dandi March (Salt March) of 1930 was led by __.", options:["Bal Gangadhar Tilak","Jawaharlal Nehru","Mahatma Gandhi","Bhagat Singh"], correct:2, trivia:"Gandhi marched 388 km in 24 days to the sea to make salt and break the British Salt Law. This act of civil disobedience inspired millions! Newspapers around the world covered it. 🧂", visual:"🧂", difficulty:"medium", hasMap:false, mapState:null },
  { id:109, subject:"history", question:"Who was the queen of Jhansi who fought bravely against the British?", options:["Ahilyabai Holkar","Razia Sultan","Rani Lakshmibai","Chennamma"], correct:2, trivia:"Rani Lakshmibai (1828-1858) was one of the leading figures of the 1857 revolt. She fought in battle even while carrying her young son on her back. She died at only 29, never surrendering! ⚔️", visual:"⚔️", difficulty:"easy", hasMap:false, mapState:null },
  { id:110, subject:"history", question:"Bhagat Singh was hanged at what age?", options:["19","21","23","25"], correct:2, trivia:"Bhagat Singh was executed by the British on 23 March 1931 at just 23 years old. His famous quote: 'They may kill me, but they cannot kill my ideas.' 23 March is observed as Shaheed Diwas! 🌹", visual:"🌹", difficulty:"medium", hasMap:false, mapState:null },
  { id:111, subject:"history", question:"The Jallianwala Bagh massacre took place in which year?", options:["1905","1915","1919","1930"], correct:2, trivia:"On 13 April 1919 in Amritsar, General Dyer ordered troops to fire on an unarmed crowd. Hundreds were killed. This horrific event shocked the world and turned many Indians against British rule. 🪴", visual:"🪴", difficulty:"hard", hasMap:false, mapState:null },
  { id:112, subject:"history", question:"Who wrote India's national anthem 'Jana Gana Mana'?", options:["Bankim Chandra Chatterjee","Rabindranath Tagore","Sarojini Naidu","Subramanya Bharati"], correct:1, trivia:"Rabindranath Tagore wrote 'Jana Gana Mana' originally as a poem and it was first sung on 27 December 1911. He was also the first Indian to win the Nobel Prize (in Literature, 1913). 🎵", visual:"🎵", difficulty:"easy", hasMap:false, mapState:null },
  { id:113, subject:"history", question:"Who wrote the national song 'Vande Mataram'?", options:["Rabindranath Tagore","Jawaharlal Nehru","Bankim Chandra Chatterjee","Sarojini Naidu"], correct:2, trivia:"'Vande Mataram' means 'I bow to thee, Mother'. Bankim Chandra wrote it in 1876 in his novel 'Anandamath'. It became a rallying cry for freedom fighters during the independence movement. 🎶", visual:"🎶", difficulty:"medium", hasMap:false, mapState:null },
  { id:114, subject:"history", question:"Who built the Red Fort in Delhi?", options:["Akbar","Humayun","Jahangir","Shah Jahan"], correct:3, trivia:"Shah Jahan built the Red Fort (Lal Qila) in 1648 as his new palace in Delhi. It's made of red sandstone and was the official residence of Mughal emperors for 200 years. India's PM hoists the flag here on Independence Day! 🏰", visual:"🏰", difficulty:"medium", hasMap:false, mapState:null },
  { id:115, subject:"history", question:"Which ancient civilisation flourished along the Indus River around 3000 BCE?", options:["Vedic Civilisation","Indus Valley Civilisation","Maurya Empire","Gupta Empire"], correct:1, trivia:"The Indus Valley Civilisation had proper city planning, drainage systems, and even standard weights and measures — all 5,000 years ago! Cities like Harappa and Mohenjo-daro were more advanced than many cities of their time. 🏺", visual:"🏺", difficulty:"medium", hasMap:false, mapState:null },
  { id:116, subject:"history", question:"Emperor Ashoka spread which religion after the Kalinga War?", options:["Hinduism","Islam","Buddhism","Jainism"], correct:2, trivia:"After the bloody Kalinga War, Ashoka was so horrified by the suffering that he embraced Buddhism and non-violence. He sent his son Mahendra and daughter Sanghamitra to spread Buddhism to Sri Lanka! 🪷", visual:"🪷", difficulty:"medium", hasMap:false, mapState:null },
  { id:117, subject:"history", question:"The Qutub Minar in Delhi was built in which era?", options:["Gupta period","Maratha period","Mughal period","Delhi Sultanate"], correct:3, trivia:"Qutub Minar was begun by Qutub-ud-din Aibak in 1193 CE and completed by Iltutmish. At 72.5 metres, it's the world's tallest brick minaret! It's been standing for over 800 years. 🗼", visual:"🗼", difficulty:"hard", hasMap:false, mapState:null },
  { id:118, subject:"history", question:"Sardar Vallabhbhai Patel is known by which title?", options:["Lion of Punjab","Father of the Nation","Iron Man of India","Tiger of Mysore"], correct:2, trivia:"Patel integrated 562 princely states into India after independence — a massive political achievement in just months! He is called the Iron Man because of his firm determination. His statue, the Statue of Unity in Gujarat, is the world's tallest at 182 metres! 🗽", visual:"🗽", difficulty:"medium", hasMap:false, mapState:null },
  { id:119, subject:"history", question:"Tipu Sultan was the ruler of which kingdom?", options:["Maratha Empire","Mysore","Hyderabad","Vijayanagara"], correct:1, trivia:"Tipu Sultan (1750-1799) was called the 'Tiger of Mysore'. He was one of the first to use war rockets and even had a mechanical tiger toy that made sounds of a tiger eating a British soldier! 🐯", visual:"🐯", difficulty:"medium", hasMap:false, mapState:null },
  { id:120, subject:"history", question:"Which event in 1857 is considered India's First War of Independence?", options:["Non-Cooperation Movement","Sepoy Mutiny (Revolt of 1857)","Dandi March","Quit India Movement"], correct:1, trivia:"The Revolt of 1857 started when Indian soldiers (sepoys) refused to use new rifle cartridges greased with animal fat. It spread across India but was ultimately suppressed by the British. 🎖️", visual:"🎖️", difficulty:"medium", hasMap:false, mapState:null },
  { id:121, subject:"history", question:"Who founded the Indian National Congress in 1885?", options:["Mahatma Gandhi","Bal Gangadhar Tilak","A.O. Hume","Gopal Krishna Gokhale"], correct:2, trivia:"Allan Octavian Hume, a retired British civil servant, helped found the INC! He wanted a platform for educated Indians to present their grievances to the British government. 📋", visual:"📋", difficulty:"hard", hasMap:false, mapState:null },
  { id:122, subject:"history", question:"The Ajanta Caves contain world-famous ancient paintings about which religion?", options:["Hinduism","Jainism","Buddhism","Sikhism"], correct:2, trivia:"The Ajanta Caves in Maharashtra (carved 2nd century BCE to 5th century CE) contain stunning Buddhist murals and sculptures. They were abandoned and hidden in the jungle until an English officer rediscovered them in 1819! 🎨", visual:"🎨", difficulty:"medium", hasMap:false, mapState:null },
  { id:123, subject:"history", question:"Which period of Indian history is called the 'Golden Age'?", options:["Maurya Empire","Gupta Empire","Mughal Empire","British Raj"], correct:1, trivia:"The Gupta Empire (320-550 CE) was India's golden age of science, math, literature, and art. Aryabhata calculated the value of Pi, proposed that Earth rotates on its axis, and invented the concept of zero! ✨", visual:"✨", difficulty:"hard", hasMap:false, mapState:null },
  { id:124, subject:"history", question:"Nalanda University — one of the world's first universities — was located in which state?", options:["UP","Bengal","Odisha","Bihar"], correct:3, trivia:"Nalanda was a famous centre of learning from the 5th to 12th centuries CE. Students from China, Korea, Japan, Tibet, and Greece came to study here! It had a library with 9 million manuscripts. 📚", visual:"📚", difficulty:"hard", hasMap:true, mapState:"Bihar" },
  { id:125, subject:"history", question:"What does the Ashoka Chakra (wheel) in India's flag represent?", options:["Progress and movement","The sun","Ancient trade routes","The ocean"], correct:0, trivia:"The Ashoka Chakra has 24 spokes representing 24 hours of the day, symbolising that there is life in movement. Emperor Ashoka put this wheel on his pillars to symbolise the Dharma Chakra (wheel of law). 🔵", visual:"🔵", difficulty:"medium", hasMap:false, mapState:null },
  { id:126, subject:"history", question:"Who was the first female Prime Minister of India?", options:["Sonia Gandhi","Sarojini Naidu","Vijaya Lakshmi Pandit","Indira Gandhi"], correct:3, trivia:"Indira Gandhi served as India's PM from 1966-1977 and again 1980-1984. She was also the first female PM in Asia! She led India to victory in the 1971 war that created Bangladesh. 💪", visual:"💪", difficulty:"easy", hasMap:false, mapState:null },
  { id:127, subject:"history", question:"Swami Vivekananda represented India at the Parliament of the World's Religions in which city?", options:["London","New York","Chicago","Paris"], correct:2, trivia:"On 11 September 1893, Vivekananda addressed the parliament starting with 'Sisters and Brothers of America!' — the crowd gave him a 2-minute standing ovation just for this greeting! 🎤", visual:"🎤", difficulty:"hard", hasMap:false, mapState:null },
  { id:128, subject:"history", question:"Dr. A.P.J. Abdul Kalam was known as the __.", options:["Father of Green Revolution","Missile Man of India","Iron Man of India","Father of White Revolution"], correct:1, trivia:"Dr. Kalam led India's satellite and missile development programmes. He became India's 11th President (2002-2007) and was adored for his simple lifestyle, love of children, and inspirational talks. 🚀", visual:"🚀", difficulty:"easy", hasMap:false, mapState:null },
  { id:129, subject:"history", question:"The Battle of Plassey (1757) marked the beginning of British rule in India. Who won it?", options:["Marathas","Hyderabad Nizam","British East India Company","Mysore"], correct:2, trivia:"The British East India Company defeated Nawab Siraj ud-Daulah of Bengal with the help of a traitor, Mir Jafar. This battle gave the British control of Bengal's vast wealth and started their conquest of India. ⚔️", visual:"⚔️", difficulty:"hard", hasMap:false, mapState:null },
  { id:130, subject:"history", question:"The famous Konark Sun Temple is in which state?", options:["Tamil Nadu","Kerala","Andhra Pradesh","Odisha"], correct:3, trivia:"The Konark Sun Temple (13th century) was built in the shape of a giant chariot with 24 wheels pulled by 7 horses representing the Sun God's chariot. UNESCO declared it a World Heritage Site in 1984! ☀️", visual:"☀️", difficulty:"medium", hasMap:true, mapState:"Odisha" },
  { id:131, subject:"history", question:"Who gave the famous slogan 'Jai Hind!'?", options:["Mahatma Gandhi","Jawaharlal Nehru","Subhas Chandra Bose","Bhagat Singh"], correct:2, trivia:"'Jai Hind' meaning 'Long live India!' became the rallying cry of the Indian National Army. Netaji Bose first used it in his broadcasts. Nehru ended his famous 'Tryst with Destiny' speech with it, and it has been used ever since! 🇮🇳", visual:"🇮🇳", difficulty:"medium", hasMap:false, mapState:null },
  { id:132, subject:"history", question:"Holi is the Hindu festival of __.", options:["Lights","Harvest","Colours","New Year"], correct:2, trivia:"Holi celebrates the victory of good over evil, associated with the story of Prahlad and Holika. The evening bonfire is called Holika Dahan. It falls in March when spring begins! 🎨", visual:"🎨", difficulty:"easy", hasMap:false, mapState:null },
  { id:133, subject:"history", question:"Diwali celebrates the return of which Hindu deity to Ayodhya?", options:["Krishna","Shiva","Hanuman","Lord Rama"], correct:3, trivia:"Diwali (Festival of Lights) marks Lord Rama's return to Ayodhya after 14 years in exile and his victory over Ravana. People light diyas (oil lamps) to guide his way. It's celebrated in October/November! 🪔", visual:"🪔", difficulty:"easy", hasMap:false, mapState:null },
  { id:134, subject:"history", question:"The Golden Temple (Harmandir Sahib) is in which city?", options:["Delhi","Ludhiana","Chandigarh","Amritsar"], correct:3, trivia:"The Golden Temple is the holiest shrine in Sikhism. Its top is covered with 750 kg of real gold! It serves free food (langar) to 100,000 people every single day regardless of religion, caste, or background. 🙏", visual:"🙏", difficulty:"easy", hasMap:false, mapState:null },
  { id:135, subject:"history", question:"Who founded Sikhism?", options:["Guru Gobind Singh","Guru Nanak Dev Ji","Guru Tegh Bahadur","Guru Angad Dev"], correct:1, trivia:"Guru Nanak Dev Ji (1469-1539) was the founder and first Guru of Sikhism. He taught equality of all humans, selfless service, and meditation on God. He travelled thousands of km on foot to spread his message. 🌟", visual:"🌟", difficulty:"easy", hasMap:false, mapState:null },
  { id:136, subject:"history", question:"The Onam festival is the harvest festival of which state?", options:["Karnataka","Tamil Nadu","Andhra Pradesh","Kerala"], correct:3, trivia:"Onam celebrates King Mahabali's annual visit to his people. The festival features a 10-day celebration with flower rangoli (Pookalam), boat races, and the Onam Sadya — a feast of 26 dishes served on banana leaves! 🌺", visual:"🌺", difficulty:"easy", hasMap:false, mapState:null },
  { id:137, subject:"history", question:"The Quit India Movement was launched by Mahatma Gandhi in which year?", options:["1920","1930","1942","1947"], correct:2, trivia:"On 8 August 1942, Gandhi gave the 'Do or Die' speech launching the Quit India Movement to demand immediate end of British rule. The British arrested him and 60,000+ other leaders the very next morning! ✊", visual:"✊", difficulty:"hard", hasMap:false, mapState:null },
  { id:138, subject:"history", question:"Mother Teresa, who served the poor in Kolkata, was originally from which country?", options:["Italy","Albania","Poland","Portugal"], correct:1, trivia:"Mother Teresa was born Agnes Gonxha Bojaxhiu in Macedonia (then part of Albania) in 1910. She came to India at 18, founded the Missionaries of Charity in Kolkata, and won the Nobel Peace Prize in 1979. 💝", visual:"💝", difficulty:"hard", hasMap:false, mapState:null },
  { id:139, subject:"history", question:"The Baisakhi festival is celebrated mainly in which region?", options:["Gujarat","Rajasthan","Bengal","Punjab"], correct:3, trivia:"Baisakhi marks the Punjabi New Year and the harvest season. In 1699, the 10th Sikh Guru, Gobind Singh, chose Baisakhi to establish the Khalsa (Sikh warrior community) — a defining moment in Sikh history! 🌾", visual:"🌾", difficulty:"easy", hasMap:false, mapState:null },
  { id:140, subject:"history", question:"Chandragupta Maurya founded which empire?", options:["Gupta Empire","Mughal Empire","Maurya Empire","Vijayanagara Empire"], correct:2, trivia:"Chandragupta Maurya (340-298 BCE) founded the first pan-Indian empire with the help of his brilliant advisor Chanakya. At its peak, the Maurya Empire covered most of the Indian subcontinent! 🏺", visual:"🏺", difficulty:"medium", hasMap:false, mapState:null },
  { id:141, subject:"history", question:"Akbar the Great was known for which progressive policy?", options:["Promoting one religion","Building the Taj Mahal","Religious tolerance and Din-i-Ilahi","Defeating the Marathas"], correct:2, trivia:"Akbar's rule (1556-1605) is considered a golden era because he welcomed scholars of all religions, married Hindu princesses, abolished the jizya tax on non-Muslims, and created Din-i-Ilahi as a blend of all religions. 🤝", visual:"🤝", difficulty:"hard", hasMap:false, mapState:null },
  { id:142, subject:"history", question:"The Elephanta Caves, famous for sculptures of Shiva, are near which city?", options:["Chennai","Kolkata","Hyderabad","Mumbai"], correct:3, trivia:"The Elephanta Caves on Elephanta Island (25 km from Mumbai) were carved around the 5th-8th centuries CE. The Portuguese renamed the island 'Elephanta' after a large stone elephant they found there! 🗿", visual:"🗿", difficulty:"medium", hasMap:false, mapState:null },
  { id:143, subject:"history", question:"Who was the first President of independent India?", options:["Dr. S. Radhakrishnan","Jawaharlal Nehru","Dr. Rajendra Prasad","Sardar Patel"], correct:2, trivia:"Dr. Rajendra Prasad served as India's first President from 1950 to 1962 — the only President to be elected to two terms! He was known for his simplicity and refusing luxuries of office. 🏛️", visual:"🏛️", difficulty:"medium", hasMap:false, mapState:null },
  { id:144, subject:"history", question:"Bal Gangadhar Tilak gave which famous declaration about independence?", options:["Give me blood, I will give you freedom","Swaraj is my birthright and I shall have it","Do or Die","Inquilab Zindabad"], correct:1, trivia:"Tilak's famous declaration 'Swaraj is my birthright!' inspired a generation of freedom fighters. He was the first to use mass celebrations like Ganesh Chaturthi and Shivaji Jayanti as platforms to spread the message of freedom. 📣", visual:"📣", difficulty:"medium", hasMap:false, mapState:null },
  { id:145, subject:"history", question:"Aryabhata, the great Indian mathematician, made which revolutionary discovery?", options:["Theory of gravity","Concept of zero and value of pi","Steam engine","Theory of relativity"], correct:1, trivia:"Aryabhata (476-550 CE) was a genius who calculated pi to 4 decimal places, calculated Earth's circumference accurately, and said Earth rotates on its axis — over 1000 years before Europeans accepted it! 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:146, subject:"history", question:"Teacher's Day in India is celebrated on which date?", options:["5 September","14 November","26 January","15 August"], correct:0, trivia:"Teacher's Day (5 September) celebrates the birthday of Dr. Sarvepalli Radhakrishnan, India's second President and a great philosopher. When students asked to celebrate his birthday, he said 'Celebrate it as Teachers Day'! 🍎", visual:"🍎", difficulty:"easy", hasMap:false, mapState:null },
  { id:147, subject:"history", question:"Children's Day in India is celebrated on which date?", options:["14 November","26 January","15 August","5 September"], correct:0, trivia:"14 November is Pandit Jawaharlal Nehru's birthday, celebrated as Children's Day (Bal Diwas) because he loved children so much. He was affectionately called 'Chacha Nehru' (Uncle Nehru) by children. 🎈", visual:"🎈", difficulty:"easy", hasMap:false, mapState:null },
  { id:148, subject:"history", question:"The Pongal festival is celebrated as a harvest festival in which state?", options:["Karnataka","Kerala","Andhra Pradesh","Tamil Nadu"], correct:3, trivia:"Pongal is a 4-day festival where a sweet rice dish (also called Pongal) is cooked in the sun and offered to the Sun God. The word 'Pongal' means 'to boil' in Tamil — when the rice boils over, people shout 'Pongal-O-Pongal!' with joy! 🌞", visual:"🌞", difficulty:"easy", hasMap:false, mapState:null },
  { id:149, subject:"history", question:"Rabindranath Tagore won the Nobel Prize in which field?", options:["Physics","Peace","Chemistry","Literature"], correct:3, trivia:"Tagore won the 1913 Nobel Prize in Literature for his collection of poems 'Gitanjali'. He was the first non-European to win the Nobel Prize in Literature. He returned his knighthood after the Jallianwala Bagh massacre. 📖", visual:"📖", difficulty:"medium", hasMap:false, mapState:null },
  { id:150, subject:"history", question:"The Indian National Flag has how many colours?", options:["2","3","4","5"], correct:1, trivia:"India's flag has 3 colours (tricolour): saffron (courage and sacrifice), white (peace and truth), and green (prosperity and faith). The navy blue Ashoka Chakra in the centre has 24 spokes. 🇮🇳", visual:"🇮🇳", difficulty:"easy", hasMap:false, mapState:null },

  // ── MATHEMATICS (151–200) ────────────────────────────────────────────────
  { id:151, subject:"mathematics", question:"What is 1/2 of 100?", options:["25","40","50","75"], correct:2, trivia:"Fractions were used by ancient Egyptians over 4,000 years ago! They used unit fractions (only 1 on top) and even had fraction hieroglyphs carved in stone. 🔢", visual:"½", difficulty:"easy", hasMap:false, mapState:null },
  { id:152, subject:"mathematics", question:"How many sides does a hexagon have?", options:["5","6","7","8"], correct:1, trivia:"Hexagons are nature's favourite shape! Honeybees build their hives with perfect hexagonal cells — because hexagons pack together with no wasted space and use the least wax. 🐝", visual:"⬡", difficulty:"easy", hasMap:false, mapState:null },
  { id:153, subject:"mathematics", question:"What is 7 × 8?", options:["54","56","48","63"], correct:1, trivia:"The most commonly confused multiplication fact is 7×8=56! A trick to remember: 5 6 7 8 = 56 = 7×8. Multiplication was used by ancient Babylonians 4,000 years ago. ✖️", visual:"✖️", difficulty:"easy", hasMap:false, mapState:null },
  { id:154, subject:"mathematics", question:"What is 144 ÷ 12?", options:["11","12","13","14"], correct:1, trivia:"144 is called a 'gross' (a dozen dozens). Division was first systematically used by the ancient Babylonians. The ÷ symbol was invented in 1659 by a Swiss mathematician. ➗", visual:"➗", difficulty:"easy", hasMap:false, mapState:null },
  { id:155, subject:"mathematics", question:"Which fraction is the largest?", options:["1/5","1/3","1/4","1/2"], correct:3, trivia:"With fractions, bigger denominator (bottom number) means smaller piece! Imagine splitting a pizza: 1/2 means one of 2 pieces (huge!), while 1/5 means one of 5 pieces (small). 🍕", visual:"🍕", difficulty:"easy", hasMap:false, mapState:null },
  { id:156, subject:"mathematics", question:"How many minutes are in 2 hours?", options:["100","110","120","130"], correct:2, trivia:"Our 60-minute hour comes from the ancient Babylonians who used a base-60 number system over 4,000 years ago! That's also why we have 60 seconds in a minute. ⏰", visual:"⏰", difficulty:"easy", hasMap:false, mapState:null },
  { id:157, subject:"mathematics", question:"What is the perimeter of a square with a side length of 5 cm?", options:["15 cm","20 cm","25 cm","10 cm"], correct:1, trivia:"Perimeter means 'measure around' — from Greek 'peri' (around) + 'metron' (measure). The same word gives us 'perimeter fence' around a sports field! 📐", visual:"📐", difficulty:"easy", hasMap:false, mapState:null },
  { id:158, subject:"mathematics", question:"What is 25% of 200?", options:["25","40","50","75"], correct:2, trivia:"25% = 1/4. A quick trick: to find 25% of any number, divide by 4! Percentages ('per cent' = per hundred) were used by Roman merchants calculating taxes 2,000 years ago. 💯", visual:"💯", difficulty:"medium", hasMap:false, mapState:null },
  { id:159, subject:"mathematics", question:"How many days are there in a leap year?", options:["364","365","366","367"], correct:2, trivia:"Earth takes 365.25 days to orbit the Sun. So every 4 years, we add an extra day (29 February) to catch up! Julius Caesar introduced leap years in 46 BCE. 📅", visual:"📅", difficulty:"easy", hasMap:false, mapState:null },
  { id:160, subject:"mathematics", question:"What is the Roman numeral for 9?", options:["VIIII","VX","IIX","IX"], correct:3, trivia:"Romans used subtraction notation: IX means 10 minus 1! The same rule applies to IV (4), XC (90), CD (400), CM (900). Roman numerals were used for 1,500 years across Europe! 🏛️", visual:"🏛️", difficulty:"medium", hasMap:false, mapState:null },
  { id:161, subject:"mathematics", question:"What is 3/4 written as a decimal?", options:["0.34","0.7","0.75","0.8"], correct:2, trivia:"To convert a fraction to decimal, divide the top by the bottom: 3 ÷ 4 = 0.75. Decimal fractions were invented by a Flemish mathematician Simon Stevin in 1585 — before that, everyone used fractions! 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:162, subject:"mathematics", question:"How many zeros are there in 'one lakh'?", options:["4","5","6","7"], correct:1, trivia:"1 lakh = 1,00,000 (five zeros). India uses the lakh-crore system: 100 lakhs = 1 crore. The word 'lakh' comes from Sanskrit 'laksha'. Most other countries use million (10 lakhs) and billion (100 crores). 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:163, subject:"mathematics", question:"What is the next prime number after 7?", options:["8","9","10","11"], correct:3, trivia:"Prime numbers are divisible only by 1 and themselves. The largest known prime number has over 24 million digits! Mathematicians use prime numbers to keep internet passwords safe. 🔐", visual:"🔐", difficulty:"medium", hasMap:false, mapState:null },
  { id:164, subject:"mathematics", question:"A square has all sides equal and all angles equal to __.", options:["45°","60°","90°","120°"], correct:2, trivia:"Squares are everywhere in architecture because right angles (90°) are the most stable. The ancient Egyptians used a 3-4-5 right triangle with ropes to create perfect right angles when building pyramids! 🔳", visual:"🔳", difficulty:"easy", hasMap:false, mapState:null },
  { id:165, subject:"mathematics", question:"How many faces does a cube have?", options:["4","5","6","8"], correct:2, trivia:"A cube has 6 faces (all squares), 8 vertices (corners), and 12 edges. A Rubik's Cube is a 3×3×3 cube with over 43 quintillion possible arrangements! 🎲", visual:"🎲", difficulty:"easy", hasMap:false, mapState:null },
  { id:166, subject:"mathematics", question:"What is the area of a rectangle 8 cm long and 5 cm wide?", options:["13 sq cm","26 sq cm","40 sq cm","80 sq cm"], correct:2, trivia:"Area = Length × Width. The concept of area was crucial for ancient Egyptians who needed to calculate field sizes after the Nile flooded and washed away boundary markers every year! 📏", visual:"📏", difficulty:"easy", hasMap:false, mapState:null },
  { id:167, subject:"mathematics", question:"According to BODMAS, what is 2 + 2 × 2?", options:["8","6","4","16"], correct:1, trivia:"BODMAS: Brackets, Orders, Division, Multiplication, Addition, Subtraction — always multiply before adding! So 2 + (2×2) = 2+4 = 6. Without these rules, the same calculation could give many different answers. 🧮", visual:"🧮", difficulty:"medium", hasMap:false, mapState:null },
  { id:168, subject:"mathematics", question:"The sum of all angles in a triangle is always __.", options:["90°","180°","270°","360°"], correct:1, trivia:"No matter what shape of triangle you draw — big, small, fat, thin — its three angles always add up to exactly 180°. This amazing fact was proved by Greek mathematician Euclid over 2,300 years ago! 🔺", visual:"🔺", difficulty:"easy", hasMap:false, mapState:null },
  { id:169, subject:"mathematics", question:"The smallest 4-digit number is __.", options:["999","1000","1001","9999"], correct:1, trivia:"1,000 (one thousand). The number system we use — with place values of ones, tens, hundreds, thousands — was invented in India and is called the Hindu-Arabic numeral system. It's used worldwide today! 🔢", visual:"🔢", difficulty:"easy", hasMap:false, mapState:null },
  { id:170, subject:"mathematics", question:"What fraction of a day is 6 hours?", options:["1/6","1/4","1/3","1/2"], correct:1, trivia:"24 hours in a day ÷ 6 = 4, so 6 hours = 1/4 of a day. A day is defined by one full rotation of Earth on its axis, which takes exactly 23 hours 56 minutes 4 seconds — not precisely 24! ⏱️", visual:"⏱️", difficulty:"medium", hasMap:false, mapState:null },
  { id:171, subject:"mathematics", question:"If 5 pencils cost ₹15, how much does 1 pencil cost?", options:["₹2","₹3","₹4","₹5"], correct:1, trivia:"Unitary method: find the cost of 1 item first, then multiply for any quantity. Indian mathematician Brahmagupta (7th century) wrote rules for arithmetic operations still used today! 📝", visual:"📝", difficulty:"easy", hasMap:false, mapState:null },
  { id:172, subject:"mathematics", question:"1 kilogram is equal to how many grams?", options:["10 g","100 g","500 g","1000 g"], correct:3, trivia:"The kilogram was defined in 1795 during the French Revolution. Until 2019, the official 1 kg standard was a platinum-iridium cylinder kept in France. Now it's defined by a universal physical constant! ⚖️", visual:"⚖️", difficulty:"easy", hasMap:false, mapState:null },
  { id:173, subject:"mathematics", question:"What is the sum of angles in a quadrilateral (4-sided shape)?", options:["180°","270°","360°","450°"], correct:2, trivia:"Any quadrilateral — square, rectangle, trapezium, kite — always has angles adding to 360°. You can prove it by cutting a quadrilateral into 2 triangles (2 × 180° = 360°)! 🔲", visual:"🔲", difficulty:"medium", hasMap:false, mapState:null },
  { id:174, subject:"mathematics", question:"What is 2 × 2 × 2 (2 cubed or 2³)?", options:["6","8","4","16"], correct:1, trivia:"2³ = 8. Exponents show how many times to multiply a number by itself. Computer storage (bytes, kilobytes, megabytes) are all powers of 2 — that's why your USB drive might be exactly 8 GB or 16 GB! 💻", visual:"💻", difficulty:"medium", hasMap:false, mapState:null },
  { id:175, subject:"mathematics", question:"What is the LCM (Least Common Multiple) of 4 and 6?", options:["2","12","24","4"], correct:1, trivia:"LCM of 4 and 6 is 12. LCM is used in real life to find when two repeating events will happen at the same time — like when two buses on different schedules will depart together! 🚌", visual:"🚌", difficulty:"medium", hasMap:false, mapState:null },
  { id:176, subject:"mathematics", question:"What is the HCF (Highest Common Factor) of 12 and 18?", options:["2","3","6","9"], correct:2, trivia:"HCF of 12 and 18 is 6. HCF helps when dividing things into equal groups — like splitting 12 apples and 18 oranges into identical gift bags with no leftovers. 🍎🍊", visual:"🍎", difficulty:"medium", hasMap:false, mapState:null },
  { id:177, subject:"mathematics", question:"What comes next in the pattern: 2, 4, 8, 16, __?", options:["18","24","32","20"], correct:2, trivia:"This is a doubling pattern (×2 each time). It grows incredibly fast! If you fold a paper in half 42 times (impossible in practice), it would be tall enough to reach the Moon! 📄", visual:"📄", difficulty:"easy", hasMap:false, mapState:null },
  { id:178, subject:"mathematics", question:"A pizza is cut into 8 equal slices. If you eat 3 slices, what fraction of the pizza is left?", options:["3/8","4/8","5/8","6/8"], correct:2, trivia:"8 - 3 = 5 slices left, so 5/8 is left. Fractions in cooking are used constantly — recipes use 1/2 cup, 3/4 teaspoon, etc. Without fractions, cooking would be a disaster! 🍕", visual:"🍕", difficulty:"easy", hasMap:false, mapState:null },
  { id:179, subject:"mathematics", question:"Roman numeral 'L' stands for which number?", options:["15","40","50","100"], correct:2, trivia:"L = 50, C = 100, D = 500, M = 1000. Romans didn't have a symbol for zero! That's one reason the Hindu-Arabic number system (with zero) eventually replaced Roman numerals worldwide. 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:180, subject:"mathematics", question:"How many lines of symmetry does a circle have?", options:["0","1","4","Infinite"], correct:3, trivia:"A circle has infinite lines of symmetry because ANY line through its centre divides it into two equal halves! The ancient Greeks were so fascinated by this perfect shape that they thought all celestial objects must be circles. ⭕", visual:"⭕", difficulty:"medium", hasMap:false, mapState:null },
  { id:181, subject:"mathematics", question:"What is the average of 10, 20, and 30?", options:["15","20","25","60"], correct:1, trivia:"Average (mean) = sum ÷ count = 60 ÷ 3 = 20. Batting average in cricket, goal average in football — averages help us compare performances fairly! 📊", visual:"📊", difficulty:"easy", hasMap:false, mapState:null },
  { id:182, subject:"mathematics", question:"How many zeros are there in one crore?", options:["5","6","7","8"], correct:2, trivia:"1 crore = 1,00,00,000 (7 zeros). India's number system uses lakhs and crores, while international notation uses millions and billions. 10 million = 1 crore. 💰", visual:"💰", difficulty:"medium", hasMap:false, mapState:null },
  { id:183, subject:"mathematics", question:"What is 1000 − 357?", options:["643","653","633","663"], correct:0, trivia:"To subtract from 1000, a quick trick: subtract from 999, then add 1! So 999-357 = 642, then +1 = 643. Mental math tricks like this were taught in ancient Indian schools. 🧮", visual:"🧮", difficulty:"medium", hasMap:false, mapState:null },
  { id:184, subject:"mathematics", question:"1 km is equal to how many metres?", options:["10 m","100 m","500 m","1000 m"], correct:3, trivia:"'Kilo' means 1000 in Greek. The metric system (with kilo, centi, milli) was invented during the French Revolution in 1795. Today, every country uses it except USA, Liberia, and Myanmar. 📏", visual:"📏", difficulty:"easy", hasMap:false, mapState:null },
  { id:185, subject:"mathematics", question:"What is the value of the digit 5 in the number 3,502?", options:["5","50","500","5000"], correct:2, trivia:"Place value is one of the most important concepts in mathematics. The digit 5 in 3,502 is in the hundreds place, so its value is 500. Ancient Indians developed the place value system we use today! 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:186, subject:"mathematics", question:"How many sides does a pentagon have?", options:["4","5","6","7"], correct:1, trivia:"'Penta' means 5 in Greek. The Pentagon building (US Department of Defense) is shaped like a pentagon and is one of the world's largest office buildings with about 25,000 employees! 🔷", visual:"🔷", difficulty:"easy", hasMap:false, mapState:null },
  { id:187, subject:"mathematics", question:"What is 0.5 + 0.75?", options:["1.0","1.20","1.25","1.5"], correct:2, trivia:"0.5 = 1/2 and 0.75 = 3/4, so 1/2 + 3/4 = 2/4 + 3/4 = 5/4 = 1.25. Decimals make adding fractions much easier — which is why they were invented! 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:188, subject:"mathematics", question:"How many minutes are in 3 hours and 45 minutes?", options:["205 min","215 min","225 min","235 min"], correct:2, trivia:"3 hours = 180 min + 45 min = 225 min. Time calculations were crucial for ancient astronomers and sailors navigating by stars. An error in time calculation could mean a ship sailed hundreds of km off course! ⏰", visual:"⏰", difficulty:"medium", hasMap:false, mapState:null },
  { id:189, subject:"mathematics", question:"A book has 200 pages. Ram has read 50 pages. What fraction of the book is still left to read?", options:["1/4","1/2","3/4","4/5"], correct:2, trivia:"200 - 50 = 150 pages left. 150/200 = 3/4. Fractions are used every day — from recipes to sports statistics to sale discounts. 📚", visual:"📚", difficulty:"easy", hasMap:false, mapState:null },
  { id:190, subject:"mathematics", question:"Which of these numbers is divisible by both 2 and 3?", options:["14","15","16","18"], correct:3, trivia:"18 ÷ 2 = 9 ✓ and 18 ÷ 3 = 6 ✓. A number is divisible by 6 if it's divisible by both 2 and 3. Divisibility rules help us find factors quickly without long division! 🔢", visual:"🔢", difficulty:"medium", hasMap:false, mapState:null },
  { id:191, subject:"mathematics", question:"How many centimetres are in 1 metre?", options:["10 cm","100 cm","1000 cm","10000 cm"], correct:1, trivia:"'Centi' means 100. A metre was originally defined as 1/10,000,000 of the distance from the North Pole to the Equator. Now it's defined by the speed of light — light travels exactly 299,792,458 metres per second! 📏", visual:"📏", difficulty:"easy", hasMap:false, mapState:null },
  { id:192, subject:"mathematics", question:"What shape do you get when you fold a square diagonally?", options:["Rectangle","Pentagon","Triangle","Trapezium"], correct:2, trivia:"Folding a square diagonally creates an isosceles right triangle with a 90° angle and two 45° angles. Origami (Japanese paper folding) uses mathematical shapes to create beautiful art! 📐", visual:"📐", difficulty:"easy", hasMap:false, mapState:null },
  { id:193, subject:"mathematics", question:"If a dozen eggs costs ₹60, how much do 3 eggs cost?", options:["₹10","₹12","₹15","₹20"], correct:2, trivia:"A dozen = 12. Cost per egg = ₹60 ÷ 12 = ₹5. So 3 eggs = 3 × ₹5 = ₹15. The word 'dozen' comes from the Latin 'duodecim' meaning twelve. 🥚", visual:"🥚", difficulty:"easy", hasMap:false, mapState:null },
  { id:194, subject:"mathematics", question:"What is the perimeter of a rectangle 10 cm long and 6 cm wide?", options:["16 cm","32 cm","60 cm","30 cm"], correct:1, trivia:"Perimeter of rectangle = 2 × (length + width) = 2 × 16 = 32 cm. Athletes training on a track need to know perimeter to count how many laps equal a certain distance! 🏃", visual:"🏃", difficulty:"easy", hasMap:false, mapState:null },
  { id:195, subject:"mathematics", question:"What is the Roman numeral for 100?", options:["L","C","D","M"], correct:1, trivia:"C = 100, from the Latin 'centum' meaning hundred. This is why words like 'century' (100 years), 'cent' (1/100 of a dollar), and 'centimetre' (1/100 of a metre) all start with 'cent'! 💯", visual:"💯", difficulty:"medium", hasMap:false, mapState:null },
  { id:196, subject:"mathematics", question:"Which of these is an odd number?", options:["246","358","791","512"], correct:2, trivia:"Odd numbers end in 1, 3, 5, 7, or 9. Even numbers end in 0, 2, 4, 6, or 8. A fun fact: the sum of the first N odd numbers always equals N². For example: 1+3+5+7 = 16 = 4²! 🔢", visual:"🔢", difficulty:"easy", hasMap:false, mapState:null },
  { id:197, subject:"mathematics", question:"What is 456 rounded to the nearest hundred?", options:["400","500","460","450"], correct:1, trivia:"456 is closer to 500 than 400 (since 56 > 50). Rounding is used in daily life: shop bills, distances, population figures. Newspaper headlines always say 'about 5 million' not '4,999,847'! 📰", visual:"📰", difficulty:"medium", hasMap:false, mapState:null },
  { id:198, subject:"mathematics", question:"A clock shows 3:00. What angle do the hands make?", options:["45°","90°","120°","180°"], correct:1, trivia:"At 3:00, the hour hand points to 3 and the minute hand to 12 — exactly 1/4 of the clock face apart. Since a full circle is 360°, one quarter = 90°. Clocks use the same geometry as protractors! 🕐", visual:"🕐", difficulty:"hard", hasMap:false, mapState:null },
  { id:199, subject:"mathematics", question:"Which number is both a perfect square AND an even number?", options:["9","16","25","49"], correct:1, trivia:"16 = 4 × 4 (perfect square) and is even. Other even perfect squares: 4, 36, 64, 100. Squares appear in architecture, art, and nature. The ancient Indians called 4 a 'sacred number' because of its square properties! 🔲", visual:"🔲", difficulty:"hard", hasMap:false, mapState:null },
  { id:200, subject:"mathematics", question:"Ascending order means arranging numbers from __.", options:["Largest to smallest","Smallest to largest","Even to odd","Random order"], correct:1, trivia:"'Ascending' comes from Latin 'ascendere' meaning to climb. Numbers climb up in ascending order! Descending means going down. Library books are arranged in ascending alphabetical order so you can find them easily. 📈", visual:"📈", difficulty:"easy", hasMap:false, mapState:null },

  // ── GENERAL KNOWLEDGE (201–250) ──────────────────────────────────────────
  { id:201, subject:"gk", question:"What is the national animal of India?", options:["Lion","Leopard","Bengal Tiger","Cheetah"], correct:2, trivia:"The Bengal Tiger was declared India's national animal in 1973 when Project Tiger was launched. There were only 1,800 tigers left then; today there are over 3,000 — a great conservation success! 🐯", visual:"🐯", difficulty:"easy", hasMap:false, mapState:null },
  { id:202, subject:"gk", question:"What is the national flower of India?", options:["Rose","Jasmine","Lotus","Marigold"], correct:2, trivia:"The Lotus (Nelumbo nucifera) grows in muddy water but blooms into a clean, beautiful flower — symbolising purity and resilience. It's sacred in Hinduism and Buddhism and is used in Ayurvedic medicine! 🪷", visual:"🪷", difficulty:"easy", hasMap:false, mapState:null },
  { id:203, subject:"gk", question:"What is the national tree of India?", options:["Neem","Peepal","Mango","Banyan"], correct:3, trivia:"The Banyan tree was chosen as national tree because of its wide-spreading roots — symbolising unity. A single banyan tree in Kolkata (Acharya Jagadish Chandra Bose Indian Botanic Garden) covers over 1.5 hectares! 🌳", visual:"🌳", difficulty:"easy", hasMap:false, mapState:null },
  { id:204, subject:"gk", question:"What is the national fruit of India?", options:["Banana","Mango","Papaya","Guava"], correct:1, trivia:"The Mango has been cultivated in India for over 4,000 years! India produces about 40% of the world's mangoes. There are over 1,500 varieties of mango in India, including Alphonso, Kesar, and Langra. 🥭", visual:"🥭", difficulty:"easy", hasMap:false, mapState:null },
  { id:205, subject:"gk", question:"What does the acronym 'ISRO' stand for?", options:["Indian Science Research Organisation","Indian Space Research Organisation","International Space Research Organisation","Indian Satellite Research Organisation"], correct:1, trivia:"ISRO was founded in 1969 by Dr. Vikram Sarabhai. India's Chandrayaan-3 became the first spacecraft to land near the Moon's south pole in August 2023 — a world first! 🚀", visual:"🚀", difficulty:"medium", hasMap:false, mapState:null },
  { id:206, subject:"gk", question:"Who was the first human to walk on the Moon?", options:["Yuri Gagarin","Buzz Aldrin","Neil Armstrong","John Glenn"], correct:2, trivia:"Neil Armstrong stepped on the Moon on 20 July 1969, saying 'That's one small step for man, one giant leap for mankind.' About 600 million people watched on TV — the largest audience for any event ever! 🌕", visual:"🌕", difficulty:"easy", hasMap:false, mapState:null },
  { id:207, subject:"gk", question:"Who invented the telephone?", options:["Thomas Edison","Nikola Tesla","Alexander Graham Bell","Guglielmo Marconi"], correct:2, trivia:"Alexander Graham Bell made the first telephone call on 10 March 1876, saying 'Mr. Watson — come here — I want to see you.' Interestingly, he refused to have a telephone in his study as it distracted him! 📞", visual:"📞", difficulty:"easy", hasMap:false, mapState:null },
  { id:208, subject:"gk", question:"Which scientist discovered gravity after (according to legend) seeing an apple fall?", options:["Albert Einstein","Galileo Galilei","Isaac Newton","Michael Faraday"], correct:2, trivia:"Isaac Newton (1643-1727) didn't just discover gravity — he described it mathematically in his book 'Principia Mathematica', which is considered one of the most important science books ever written! 🍎", visual:"🍎", difficulty:"easy", hasMap:false, mapState:null },
  { id:209, subject:"gk", question:"Who invented the electric light bulb?", options:["Alexander Graham Bell","Nikola Tesla","Michael Faraday","Thomas Edison"], correct:3, trivia:"Edison tested over 1,000 materials before finding that carbonised bamboo worked as a filament. When asked about failures, he said: 'I have not failed. I've just found 10,000 ways that won't work.' 💡", visual:"💡", difficulty:"easy", hasMap:false, mapState:null },
  { id:210, subject:"gk", question:"The Wright Brothers made the first successful powered aeroplane flight in which year?", options:["1893","1898","1903","1910"], correct:2, trivia:"Orville and Wilbur Wright flew the first powered aircraft 'Flyer' at Kitty Hawk, USA, on 17 December 1903. The flight lasted just 12 seconds and covered 36 metres — barely longer than a school bus! ✈️", visual:"✈️", difficulty:"medium", hasMap:false, mapState:null },
  { id:211, subject:"gk", question:"What is the fastest land animal in the world?", options:["Lion","Horse","Cheetah","Leopard"], correct:2, trivia:"The cheetah can accelerate from 0 to 112 km/h in just 3 seconds — faster than most sports cars! But it can only run at top speed for about 20-30 seconds before overheating. 🐆", visual:"🐆", difficulty:"easy", hasMap:false, mapState:null },
  { id:212, subject:"gk", question:"What is the largest animal in the world?", options:["African Elephant","Whale Shark","Blue Whale","Giant Squid"], correct:2, trivia:"The Blue Whale is the largest animal EVER to exist on Earth — larger than any dinosaur! A blue whale's heart is the size of a small car, and its tongue weighs as much as an elephant. 🐋", visual:"🐋", difficulty:"easy", hasMap:false, mapState:null },
  { id:213, subject:"gk", question:"India's national sport is __.", options:["Cricket","Kabaddi","Football","Hockey"], correct:3, trivia:"Field Hockey is India's national sport. India's hockey team is legendary — they won 8 Olympic gold medals between 1928 and 1980! The team was led by legendary players like Major Dhyan Chand, called the 'Wizard of Hockey'. 🏑", visual:"🏑", difficulty:"medium", hasMap:false, mapState:null },
  { id:214, subject:"gk", question:"Sachin Tendulkar is known as the __.", options:["Tiger of Cricket","God of Cricket","Father of Cricket","Master of Cricket"], correct:1, trivia:"Sachin Tendulkar holds the records for most runs and most centuries in both Test and ODI cricket. He scored 100 international centuries! He played for India from age 16 to 40, spanning 24 years. 🏏", visual:"🏏", difficulty:"easy", hasMap:false, mapState:null },
  { id:215, subject:"gk", question:"International Yoga Day is observed on which date?", options:["21 March","21 May","21 June","21 September"], correct:2, trivia:"21 June (the longest day of the year in the Northern Hemisphere) was declared International Yoga Day by the UN in 2015 on India's proposal. Yoga originated in India over 5,000 years ago! 🧘", visual:"🧘", difficulty:"medium", hasMap:false, mapState:null },
  { id:216, subject:"gk", question:"World Environment Day is observed on which date?", options:["5 April","5 May","5 June","5 July"], correct:2, trivia:"World Environment Day (5 June) is the United Nations' main vehicle for raising awareness about the environment. It was established in 1972 following the Stockholm Conference on the Human Environment. 🌱", visual:"🌱", difficulty:"medium", hasMap:false, mapState:null },
  { id:217, subject:"gk", question:"The Olympic Games are held once every __ years.", options:["2","3","4","5"], correct:2, trivia:"The modern Olympic Games were revived in Athens, Greece, in 1896 by Pierre de Coubertin. The ancient Greek Olympics were held every 4 years starting from 776 BCE — a 2,800-year tradition! 🥇", visual:"🥇", difficulty:"easy", hasMap:false, mapState:null },
  { id:218, subject:"gk", question:"How many players are in a cricket team?", options:["9","10","11","12"], correct:2, trivia:"Cricket teams have 11 players, just like football! Cricket originated in England in the 16th century and became India's most popular sport during British rule. The Cricket World Cup is the 3rd most watched sporting event in the world. 🏏", visual:"🏏", difficulty:"easy", hasMap:false, mapState:null },
  { id:219, subject:"gk", question:"Mary Kom, the famous Indian boxer, is from which state?", options:["Assam","Manipur","Nagaland","Meghalaya"], correct:1, trivia:"M.C. Mary Kom is a six-time World Amateur Boxing Champion and Olympic bronze medalist. Born in Manipur, she started boxing secretly, fearing her father would disapprove! She is a mother of three. 🥊", visual:"🥊", difficulty:"medium", hasMap:false, mapState:null },
  { id:220, subject:"gk", question:"The number of planets in our solar system is __.", options:["7","8","9","10"], correct:1, trivia:"In 2006, Pluto was reclassified from a planet to a 'dwarf planet', leaving 8 planets: Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune. Some scientists still debate whether Pluto should be a planet! 🪐", visual:"🪐", difficulty:"easy", hasMap:false, mapState:null },
  { id:221, subject:"gk", question:"India won the Cricket World Cup for the first time in which year?", options:["1975","1979","1983","1987"], correct:2, trivia:"In 1983, Kapil Dev's India shocked the world by beating the West Indies (2-time champions) in the final at Lord's, London! India's first World Cup win inspired a generation of cricketers including Sachin Tendulkar. 🏆", visual:"🏆", difficulty:"medium", hasMap:false, mapState:null },
  { id:222, subject:"gk", question:"The Eiffel Tower is located in which city?", options:["London","Rome","Berlin","Paris"], correct:3, trivia:"The Eiffel Tower was built in 1889 for the Paris World Fair and was meant to be demolished after 20 years! Gustave Eiffel saved it by installing a radio antenna on top. It's now the most-visited paid monument in the world. 🗼", visual:"🗼", difficulty:"easy", hasMap:false, mapState:null },
  { id:223, subject:"gk", question:"What does 'www' in a website address stand for?", options:["World Wide Watch","World Wide Web","World Web Window","Wide World Weblink"], correct:1, trivia:"The World Wide Web was invented by Tim Berners-Lee in 1989. He invented it to help scientists at CERN share information. He gave it to the world for free — never charging a patent! What a gift! 💻", visual:"💻", difficulty:"medium", hasMap:false, mapState:null },
  { id:224, subject:"gk", question:"Google was founded by which two people?", options:["Bill Gates & Steve Jobs","Mark Zuckerberg & Jack Dorsey","Larry Page & Sergey Brin","Jeff Bezos & Elon Musk"], correct:2, trivia:"Larry Page and Sergey Brin started Google in 1998 as a research project at Stanford University. They originally named it 'BackRub'! Google processes over 8.5 billion searches per day. 🔍", visual:"🔍", difficulty:"medium", hasMap:false, mapState:null },
  { id:225, subject:"gk", question:"The Great Wall of China was primarily built to __.", options:["Show off China's power","Protect against northern invasions","Mark trade routes","Create tourist attraction"], correct:1, trivia:"The Great Wall stretches over 21,000 km (though much is ruined). It was built over 2,000 years by millions of workers. Contrary to popular belief, it is NOT visible from space with the naked eye. 🏯", visual:"🏯", difficulty:"medium", hasMap:false, mapState:null },
  { id:226, subject:"gk", question:"Which animal is the symbol of the World Wildlife Fund (WWF)?", options:["Tiger","Polar bear","Giant Panda","African Elephant"], correct:2, trivia:"The Giant Panda was chosen as WWF's symbol in 1961 because it's universally loved, distinctive in black and white (making it cheap to print logos), and was critically endangered. There are now about 1,800 pandas in the wild! 🐼", visual:"🐼", difficulty:"medium", hasMap:false, mapState:null },
  { id:227, subject:"gk", question:"Saina Nehwal and P.V. Sindhu are famous Indian players of which sport?", options:["Tennis","Table Tennis","Badminton","Squash"], correct:2, trivia:"Saina Nehwal became world No. 1 in badminton in 2015 — the first Indian to do so. P.V. Sindhu won the Badminton World Championship gold in 2019 and two Olympic medals (silver + bronze). 🏸", visual:"🏸", difficulty:"easy", hasMap:false, mapState:null },
  { id:228, subject:"gk", question:"India's Chandrayaan-3 made which historic achievement in 2023?", options:["First spacecraft to orbit Mars","First to land on the Moon's south pole","First to reach Jupiter","First to photograph a black hole"], correct:1, trivia:"On 23 August 2023, Chandrayaan-3's Vikram lander touched down near the Moon's south pole — a region no other country had reached before! The rover Pragyan explored the lunar surface for 14 days. 🌕🇮🇳", visual:"🌕", difficulty:"medium", hasMap:false, mapState:null },
  { id:229, subject:"gk", question:"Albert Einstein is famous for which scientific theory?", options:["Theory of Evolution","Theory of Gravity","Theory of Relativity","Theory of Atoms"], correct:2, trivia:"Einstein's famous equation E=mc² shows that energy and mass are interchangeable! He published it in 1905 when he was just 26 years old. He was once offered the Presidency of Israel but declined. 💡", visual:"💡", difficulty:"medium", hasMap:false, mapState:null },
  { id:230, subject:"gk", question:"Which is the tallest statue in the world (as of 2024)?", options:["Statue of Liberty","Christ the Redeemer","Statue of Unity","Spring Temple Buddha"], correct:2, trivia:"The Statue of Unity in Gujarat, India, stands 182 metres tall — almost twice the height of the Statue of Liberty! It depicts Sardar Vallabhbhai Patel and was inaugurated in 2018 on his birth anniversary. 🗽", visual:"🗽", difficulty:"medium", hasMap:false, mapState:null },
  { id:231, subject:"gk", question:"What currency does Japan use?", options:["Yuan","Won","Yen","Ringgit"], correct:2, trivia:"Japan's Yen (¥) is one of the world's most traded currencies. Japan is famous for being the first Asian country to industrialise, its manga comics, anime, sushi, and the bullet train (Shinkansen) running at 320 km/h! 🍣", visual:"🍣", difficulty:"medium", hasMap:false, mapState:null },
  { id:232, subject:"gk", question:"How many players are in a football (soccer) team?", options:["9","10","11","12"], correct:2, trivia:"Football is the world's most popular sport with 4 billion fans! The FIFA World Cup is the most watched sporting event on Earth — the 2022 World Cup final had over 1.5 billion viewers. ⚽", visual:"⚽", difficulty:"easy", hasMap:false, mapState:null },
  { id:233, subject:"gk", question:"Which planet has the most moons in our solar system?", options:["Jupiter","Saturn","Uranus","Neptune"], correct:1, trivia:"Saturn has 146 known moons (as of 2024) — the most of any planet! Its largest moon, Titan, is bigger than the planet Mercury and has a thick atmosphere with rivers and lakes of liquid methane. 🪐", visual:"🪐", difficulty:"hard", hasMap:false, mapState:null },
  { id:234, subject:"gk", question:"The Panchatantra — an ancient Indian collection of animal stories — was originally written in which language?", options:["Hindi","Tamil","Sanskrit","Pali"], correct:2, trivia:"The Panchatantra was written around 200 BCE and has been translated into over 50 languages — making it one of the most widely translated books in the world! Many of Aesop's Fables are similar to Panchatantra stories. 📖", visual:"📖", difficulty:"hard", hasMap:false, mapState:null },
  { id:235, subject:"gk", question:"P.T. Usha, the 'Payyoli Express', is a legendary Indian athlete in which event?", options:["Swimming","Boxing","Sprinting (running)","Javelin throw"], correct:2, trivia:"P.T. Usha from Kerala is called the 'Queen of Indian Track and Field'. In the 1984 Olympics, she missed a bronze medal by just 1/100th of a second — one of sport's most heartbreaking near-misses. She was elected to the Rajya Sabha and became President of the Indian Olympic Association! 🏃‍♀️", visual:"🏃‍♀️", difficulty:"medium", hasMap:false, mapState:null },
  { id:236, subject:"gk", question:"What does 'LED' in LED light bulb stand for?", options:["Light Emitting Diode","Long Energy Device","Low Electricity Design","Light Energy Display"], correct:0, trivia:"LED lights use 75% less energy than traditional bulbs and last 25 times longer! They were invented in 1962. Switching all India's lights to LED (done through Ujala scheme) saves billions of units of electricity every year. 💡", visual:"💡", difficulty:"medium", hasMap:false, mapState:null },
  { id:237, subject:"gk", question:"Milkha Singh, the 'Flying Sikh', was a legendary Indian athlete in which sport?", options:["Football","Swimming","Boxing","Athletics (sprinting)"], correct:3, trivia:"Milkha Singh (1929-2021) won 4 Asian Games gold medals and represented India in 3 Olympics. In the 1960 Olympics 400m final, he led the race but looked back — and missed the bronze by 0.1 second. His life story became the movie 'Bhaag Milkha Bhaag'! 🏅", visual:"🏅", difficulty:"medium", hasMap:false, mapState:null },
  { id:238, subject:"gk", question:"Which country is called the 'Land of the Rising Sun'?", options:["China","South Korea","Thailand","Japan"], correct:3, trivia:"Japan's name in Japanese is 'Nippon' or 'Nihon' — meaning 'origin of the sun'. Because Japan is east of China, Chinese travellers saw the sun rise from Japan's direction, giving it this poetic name. 🌅", visual:"🌅", difficulty:"easy", hasMap:false, mapState:null },
  { id:239, subject:"gk", question:"The human body has approximately how many bones?", options:["106","156","206","256"], correct:2, trivia:"Babies are born with 270-300 bones, but many fuse together as you grow. By adulthood, you have 206. More than half of your bones (106!) are in your hands and feet. 🦴", visual:"🦴", difficulty:"medium", hasMap:false, mapState:null },
  { id:240, subject:"gk", question:"What is the currency of India?", options:["Taka","Rupee","Rial","Dollar"], correct:1, trivia:"The Indian Rupee (₹) symbol was designed by D. Udaya Kumar and adopted in 2010. It's a combination of the Devanagari letter 'Ra' and the Latin letter 'R'. India's economy is the world's 5th largest! 💰", visual:"💰", difficulty:"easy", hasMap:false, mapState:null },
  { id:241, subject:"gk", question:"The UN (United Nations) was founded after which major world event?", options:["World War I","The Great Depression","World War II","The Cold War"], correct:2, trivia:"The United Nations was founded on 24 October 1945 after WWII, with 51 countries, to prevent future wars. Today it has 193 member states — almost every country on Earth! UN Day is celebrated on 24 October. 🌐", visual:"🌐", difficulty:"medium", hasMap:false, mapState:null },
  { id:242, subject:"gk", question:"What is the national emblem of India?", options:["Lotus","Tiger","Ashoka Chakra","Lion Capital of Ashoka"], correct:3, trivia:"India's emblem is the Lion Capital of Ashoka — a sculpture of 4 lions standing back to back, originally from a pillar at Sarnath. Below the lions is the Ashoka Chakra and the motto 'Satyameva Jayate' (Truth Alone Triumphs). 🏛️", visual:"🏛️", difficulty:"medium", hasMap:false, mapState:null },
  { id:243, subject:"gk", question:"Which Indian launched the Mars Orbiter Mission (Mangalyaan) making India the first country to reach Mars on its first attempt?", options:["DRDO","ISRO","HAL","BARC"], correct:1, trivia:"On 24 September 2014, ISRO's Mangalyaan successfully entered Mars orbit — the cheapest Mars mission ever ($74 million), costing less than the Hollywood movie 'Gravity'! India was the FIRST country to succeed on its first Mars attempt. 🔴🚀", visual:"🚀", difficulty:"medium", hasMap:false, mapState:null },
  { id:244, subject:"gk", question:"Sunita Williams, who has spent over 300 days in space, has Indian heritage from which state?", options:["Maharashtra","Gujarat","Rajasthan","Kerala"], correct:1, trivia:"Sunita Williams' father, Deepak Pandya, is from Gujarat. She holds the record for most spacewalks by a woman (7 spacewalks). She carried a copy of the Bhagavad Gita and samosas to space! 🚀", visual:"🚀", difficulty:"hard", hasMap:false, mapState:null },
  { id:245, subject:"gk", question:"What is the approximate human population of the world (as of 2024)?", options:["5 billion","6 billion","8 billion","10 billion"], correct:2, trivia:"Earth's population hit 8 billion in November 2022. It took 200,000 years for humans to reach 1 billion (1804), but only 12 years to go from 7 to 8 billion! Experts expect the population to peak around 10-11 billion. 🌍", visual:"🌍", difficulty:"medium", hasMap:false, mapState:null },
  { id:246, subject:"gk", question:"Which festival is celebrated with the immersion of Ganesha idols?", options:["Navratri","Diwali","Ganesh Chaturthi","Holi"], correct:2, trivia:"Ganesh Chaturthi is celebrated for 10 days, mainly in Maharashtra! Bal Gangadhar Tilak turned it into a mass public festival in 1893 as a way for people to gather and plan freedom struggle activities. 🐘", visual:"🐘", difficulty:"easy", hasMap:false, mapState:null },
  { id:247, subject:"gk", question:"The Amazon River is in which continent?", options:["Africa","Asia","Europe","South America"], correct:3, trivia:"The Amazon carries more water than the next 7 largest rivers combined! It's so wide in places that from one bank, you cannot see the other side. The Amazon basin is home to 10% of ALL species on Earth! 🌿", visual:"🌿", difficulty:"easy", hasMap:false, mapState:null },
  { id:248, subject:"gk", question:"Which is the largest democracy in the world?", options:["USA","China","Russia","India"], correct:3, trivia:"India is called the world's largest democracy because it has the most eligible voters — over 960 million! India's 2024 general election was the world's largest democratic exercise, with 642 million people voting. 🗳️", visual:"🗳️", difficulty:"easy", hasMap:false, mapState:null },
  { id:249, subject:"gk", question:"The Northern Lights (Aurora Borealis) can be seen near which region?", options:["Equator","Tropics","Poles (Arctic/Antarctic)","Deserts"], correct:2, trivia:"Aurora Borealis happens when solar particles hit Earth's magnetic field and glow. The lights appear in green, pink, and purple. Best places to see them: Norway, Iceland, Finland, Canada, and Alaska! 🌌", visual:"🌌", difficulty:"medium", hasMap:false, mapState:null },
  { id:250, subject:"gk", question:"India's PARAM supercomputer was developed by which organisation?", options:["IIT Bombay","ISRO","C-DAC","DRDO"], correct:2, trivia:"C-DAC (Centre for Development of Advanced Computing) developed PARAM in 1991 when the USA refused to sell India supercomputers. India proved it could build its own! PARAM Siddhi is now ranked among the world's top 500 supercomputers. 💻", visual:"💻", difficulty:"hard", hasMap:false, mapState:null }
];
